INSERT INTO public.coupons VALUES ('467557c5-ef1c-410c-b426-b3197825d217', '31640105-56f9-43ab-8204-465c8717d731', 'MAISMAIS', NULL, true, '2026-03-29 19:57:00.869715+00', 'Ganhe 10% off em comprar a partir de R$ 150 (limite de R$ 150) ', '10%', '10%', '', 'Ganhe 10% off em comprar a partir de R$ 150 (limite de R$ 150) Cupom de desconto: ALOCUPOM Não válida para produtos de Amamentação (https://www.amazon.com.br/gp/browse.html?node=122326861011), Kindle (https://www.amazon.com.br/gp/browse.html?node=5475881011), Echo (https://www.amazon.com.br/gp/browse.html?node=19877613011), Projetos (https://www.amazon.com.br/gp/browse.html?node=12320558011), Projetos (https://www.amazon.com.br/gp/browse.html?node=121320563011). A oferta é válida para pedidos a partir de R$ 150 (cento e cinquenta reais) de produtos elegíveis, excluindo custos de envio e de embalagem para presente. No caso de devolução parcial, a promoção será aplicada apenas ao total dos produtos não devolvidos, desde que o valor seja igual ou superior a R$ 150 (cento e cinquenta reais). O benefício máximo que você pode receber com esta promoção é limitado a R$ 150 (cento e cinquenta reais). Esta promoção é por tempo limitado, expirando às 19:00 do dia 29/03/2026 ou enquanto durarem os estoques Esta promoção somente poderá ser utilizada para compra de produtos físicos. Taxas de frete aplicáveis conforme política vigente no momento da compra. Cada cliente/conta poderá usufruir desta promoção apenas uma vez, em um único pedido. Os produtos devem ser comprados em um único pedido e enviados utilizando o mesmo tipo de frete para um único endereço. Esta promoção não pode ser combinada com outras promoções ou ofertas. O preço exibido na página de detalhes de cada um dos produtos elegíveis será o valor integral, sem o desconto. Na página de finalização do pedido, você visualizará o desconto sobre os produtos elegíveis. Em caso de devolução de algum produto adquirido nesta promoção, o valor a ser reembolsado será o efetivamente pago, e não o valor original do produto fora da promoção. Itens colocados no Carrinho cuja compra não seja concluída durante o período da promoção deixarão de ser elegíveis após o término da promoção. Esta promoção pode ser revogada ou alterada a qualquer momento pela Amazon.com.br. Esta oferta é individual e intransferível, não pode ser vendida ou resgatada em dinheiro. Para fins de emissão de recibo ou outro documento fiscal, o valor equivalente ao desconto concedido poderá ser distribuído entre diversos produtos. Em caso de violação de qualquer destes termos e condições, a promoção perderá a validade A seleção dos itens elegíveis poderá ser alterada a qualquer tempo, independentemente de aviso prévio. Essa oferta não é válida para produtos desta página https://www.amazon.com.br/b?ie=UTF8&node=122326861011 Veja mais as condições de uso e informações de como resgatar um cupom de desconto em https://www.amazon.com.br/gp/help/customer/display.html?nodeId=201895180', false, 0, '', '2026-03-29 19:57:00.869715+00', NULL, '2026-03-29 22:00:00+00');
