INSERT INTO public.products VALUES ('fdcf0f14-b63d-42e0-ae79-ac2552282bf6', 'ROMANTIC CROWN Copo Térmico Inox Portátil 1200ml/600ml/1.2L Garrafa Térmica Inoxidável com Tampa e Canudo', '<p>🔥Manter quente : 12H   ❄️Manter gelo : 24H</p><p>- Peso : 1200ml/550g | 600ml/360g</p><p>- Cor : Creme/Rosa Claro/Preto/Vermelho/Rosa escuro</p><p>- Estilo : Resistente a vazamentos, isolada a vácuo</p><p>- Recomendado : Água/suco/chá gelado/Bebida quente</p><p>- Atenção: o copo de 600 ml não tem asa; apenas o copo de 1200 ml tem asa</p><p><br></p><p>📦 Conteúdo da Embalagem: </p><p>1 x Copo de 1200ml/600ml</p><p>1 x Tampa do Copo</p><p>1 x Canudo de Aço Inoxidável (Atualização do Produto)</p><p>1 x Capinha de Silicone para Canudo (Atualização do Produto)</p><p>1 x Escova para Canudo (Atualização do Produto)</p><p><br></p><p>🏆TAMANHO EXTRA GRANDE: </p><p>Romantic Crown Copo Térmico tem capacidade de até 40 onças, sendo perfeito para quem precisa beber bastante de suas bebidas. Se você prefere um copo de café gelado, um refrescante chá gelado ou uma sopa quente e substancial, refrigerantes, água ou leite, este copo é a sua escolha ideal.</p><p><br></p><p>🗑️Design Ecológico e Higiênico:</p><p>Romantic Crown Copo Térmico é projetado com foco na durabilidade, evitando o uso de garrafas plásticas descartáveis e canudos. O copo utiliza canudos de aço inoxidável e capas protetoras de silicone, com a tampa apresentando um design de rosca dupla. A abertura do canudo é projetada para evitar respingos, e o selo é utilizado para fixar o canudo reutilizável, enquanto a abertura para bebida e o topo da tampa aumentam a proteção contra vazamentos.</p><p><br></p><p>🥇Aço inoxidável a vácuo duplo:</p><p>Romantic Crown Copo Térmico é produzido em 304 aço inoxidável com uma técnica de parede dupla e vácuo entre as paredes, conservando sua bebida por mais tempo. Mantém as bebidas frias por até 24 horas e quentes por até 12 horas. O aço 18/8 evita que os copos ou canecas fiquem com cheiro e gosto de bebidas e alimentos.</p><p><br></p><p>💧Fácil de Limpar: </p><p>O copo vem com “canudo de aço inoxidável” e “capa protetora de silicone”, podendo ser limpo com “uma escova de limpeza”. Reduza o tempo se curvando sobre a pia e tenha mais tempo para fazer o que você ama. Limpar o copo e a tampa não poderia ser mais simples, basta colocá-los na lava-louças. Ao contrário das garrafas plásticas que retêm manchas e odores, este copo metálico parecerá novo.</p><p><br></p><p>🎁Presente Perfeito:</p><p>Romantic Crown Copo Térmico é o presente perfeito para bons amigos, familiares, amantes, colegas, vizinhos e parceiros de negócios, especialmente para aqueles que precisam manter uma boa hidratação ou que têm dificuldade em se reabastecer. Seja no Dia dos Namorados, Dia das Mães, Dia dos Pais, Natal, Ação de Graças, Páscoa ou aniversários, este copo é uma escolha excelente, permitindo que você expresse carinho e amor em datas especiais.</p><p><br></p><p>(Garantia do vendedor: 30 dias)</p>', 39.98, 49.98, 33, 'https://cf.shopee.com.br/file/br-11134207-81ztc-mj2ddyi3zfgi6a', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7680479737627378.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.9069651944189062.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7406187774776257.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3745469439165241.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.06662447064288157.webp}', NULL, 'Romantic.Crown.03', 'https://s.shopee.com.br/1gE9fpfXee', 4.9, 0, 3, true, NULL, '2026-03-25 12:58:49.303185+00', '2026-03-30 02:51:09.102544+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 20.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 11, 10635, '[]', NULL, '{}', '{}');
