INSERT INTO public.products VALUES ('32755277-c0c4-4aa9-886a-d30441180cfc', 'Ovo de Páscoa Kit Kat Nestlé 332g', '<p>Ovo de Páscoa Kitkat Nestlé Chocolate Saboroso Crocante A época mais doce do ano, a PÁSCOA! A Páscoa ou Domingo da Ressurreição é uma festividade religiosa que celebra o retorno de Jesus, ocorrida no terceiro dia após sua crucificação na cruz. Um momento muito especial para reunir todas as famílias e compartilhar muitos doces e chocolates. A linha Kit Kat da Nestlé é conhecida por sua qualidade e sabor inconfundível, e este ovo de Páscoa não é exceção. Transforme a sua Páscoa em um momento ainda mais especial com este delicioso ovo que combina o melhor do chocolate com a crocância única do wafer KitKat. Prepare-se para uma Páscoa memorável com o Ovo de Páscoa Kitkat Nestlé. Uma opção clássica que nunca decepciona, ideal para criar momentos de alegria e satisfação. ITENS INCLUSOS: 1x - Ovo de Páscoa Kitkat Nestlé 332g</p>', 119.99, 131.77, 9, 'https://m.media-amazon.com/images/I/613bTlC7q9L._AC_UL320_.jpg', '{https://m.media-amazon.com/images/I/613bTlC7q9L._AC_UL320_.jpg}', NULL, 'Amazon Brasil', 'https://amzn.to/4tgPsh3', 3.6, 0, 1, true, NULL, '2026-03-28 23:52:11.48235+00', '2026-03-29 12:58:50.725137+00', 'eee4c1cb-9b67-4f42-84ef-6637845a5076', '2a4ae68d-a7c8-486d-9245-57b2daf544b6', '31640105-56f9-43ab-8204-465c8717d731', NULL, 8.9, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '4aefe9fb-8c07-4342-9160-f0a65922c4ad', 'B08L6Y2X5Q', 13, NULL, NULL, NULL, '{"prime": false, "shipping_details": "Consultar frete"}', '{}');
