INSERT INTO public.products VALUES ('db53e831-ff37-4be0-a0f4-b7a61a44ffbd', 'Tapete Passadeira 2,00x0,60 Quarto Pé De Cama Luxo Conforto', 'O Tapete Passadeira 2,00x0,60 Quarto Pé De Cama Luxo Conforto da marca Dhalishop é a escolha ideal para quem busca praticidade e sofisticação em ambientes internos. Com um design elegante e moderno, ele é perfeito para corredores, quartos e salas, proporcionando um toque acolhedor e estiloso aos espaços.

Feito em poliéster, este tapete felpudo possui um pelo alto extra macio, garantindo conforto sob os pés. Seu modelo versátil e personalizável permite que você o adapte ao seu estilo pessoal, tornando-o um elemento único na decoração da sua casa.

Embora não seja um produto sanitizante, a sua qualidade e resistência o tornam fácil de cuidar e manter. Com características que permitem que ele seja rolável, este tapete é prático e funcional, ideal para quem valoriza a facilidade no dia a dia sem abrir mão da estética.

Transforme a sua casa com o Tapete Passadeira Dhalishop, que combina beleza e conforto em um só produto. Ideal para quem deseja criar ambientes aconchegantes e cheios de estilo.

Tapete Felpudo para Sala / Cozinha / Escritório / Quarto

Proporcionam uma bela decoração com estilo, transformando qualquer ambiente!
Elegante e moderno, oferecendo um ambiente aconchegante e com estilo
Confortável e macio proporcionando o bem-estar para você e sua família
Superfície em poliéster facilitando a limpeza e manutenção
Material sintético de grande durabilidade.

Especificações

Material: 100% Poliéster
Base: Antiderrapante
Mesclada (mesclas de cores)
Acabamento: Viés reforçado
Altura dos pelos: até 4 cm de comprimento
Toque da superfície: Suave

Dimensões Aproximadas

 Altura: 200cm
 Largura: 60cm

Por ser um produto com acabamento em viés e importado pode haver diferença no tamanho de até 10%.

Limpeza: Para uma maior conservação do seu tapete, recomendamos o uso regular de aspirador de pó, lavagem da superfície (pelos) somente com espuma de sabão neutro ou lavagem profissional por extração. Métodos que evitam contato excessivo da base do tapete com água. 

Qualquer duvida estamos a disposição.

Garantia do vendedor: 30 dias', 38, 44, NULL, 'https://http2.mlstatic.com/D_NQ_NP_2X_668827-MLB93769055804_102025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_668827-MLB93769055804_102025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_869503-MLB86329772657_062025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_754770-MLB86329563639_062025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_873136-MLB86015999074_062025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_625720-MLB86330370253_062025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_988642-MLB86329583771_062025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_889689-MLB93769065652_102025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp,https://http2.mlstatic.com/D_NQ_NP_2X_987466-MLB93769065906_102025-F-tapete-passadeira-200x060-quarto-pe-de-cama-luxo-conforto.webp}', 'Novo', 'Mirage Decor', 'https://meli.la/2Lnc7sM', 4.4, 0, 0, true, NULL, '2026-03-27 21:24:21.504209+00', '2026-03-27 21:26:44.476691+00', 'c9a99416-50ce-413b-ba01-2d93742462c5', NULL, '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 13.6, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 20, 100, '[{"name": "Cor", "value": "Disponível"}]', 99, '{"cashback": "", "meli_plus": false, "variations": [{"group": "Cor", "options": []}], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('60467af5-058e-4e64-a766-f8d0889d0acb', 'Smart Tv Philips 55 4k 55pug7300 Comando De Voz Bluetooth', 'Experimente a revolução da visualização com a Smart TV Philips 55" 4K 55PUG7300, uma verdadeira obra-prima da tecnologia. 

Com uma resolução 4K UHD e uma impressionante relação de contraste de 1:200000, cada cena ganhará vida com detalhes vibrantes e cores ricas. Seu sistema DLED proporciona um brilho de 250 cd/m2, garantindo uma experiência visual excepcional em qualquer ambiente.

Equipada com um processador de 4 núcleos e uma taxa de atualização de 60 Hz, essa TV oferece tempos de resposta rápidos e uma navegação fluida por meio do sistema operativo Titan OS. Conta com suporte para assistentes virtuais como Alexa e Apple Home, possibilitando um controle por voz simplificado. Além disso, o armazenamento de 8 GB permite que você baixe seus aplicativos favoritos, como Netflix, YouTube e HBO, diretamente na TV.

Com conectividade Bluetooth e Wi-Fi, a 55PUG7300 oferece fácil acesso a uma variedade de opções de entretenimento e multi-conexões com dispositivos. Seus recursos de áudio incluem Dolby Atmos e DTS-X, proporcionando uma experiência sonora imersiva que complementa a visualização. 

Com um design moderno e elegante, essa TV é uma adição perfeita para qualquer sala de estar.', 2299, 3449, 40, 'https://http2.mlstatic.com/D_NQ_NP_2X_651129-MLA92926667074_092025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_651129-MLA92926667074_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_677111-MLA92926072818_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_723947-MLA92926687014_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_757442-MLA92926072822_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_930104-MLA92926825274_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_903954-MLA92926290956_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_798987-MLA92926072828_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_987009-MLA92926825224_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_908101-MLA92926072832_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_834120-MLA93340279261_092025-F.webp}', 'Novo', 'Loja oficial Eshop', 'https://meli.la/32mjJ1E', 4.7, 0, 6, true, NULL, '2026-03-24 01:44:48.951482+00', '2026-03-26 12:13:04.890988+00', '9336d222-8a26-427b-9e2d-d9e75457a042', '403c5506-f467-412c-a92c-e48972857671', '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 33.3, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 5, 1000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
