INSERT INTO public.products VALUES ('9016cde9-ce2b-4eef-9b4a-dfd1bd88d5aa', 'Ovo de Páscoa Ao Leite Chocolate Premium Garoto 250g Ovos de Páscoa Barato Envio Rápido Premium', '<p>---------------- Envio Imediato -----------------------</p><p><br></p><p>====== ATENÇÃO TODOS OS OVOS SÃO ENVIADOS COM CAIXA DE ISOPOR PARA NAO QUEBRAR NO TRANSPORTE =========</p><p><br></p><p>Ovo de Páscoa 250g chocolate de alta qualidade, é delicioso! </p><p><br></p><p>Chocolate de Qualidade: Feito com os melhores ingredientes, nosso chocolate é rico, cremoso e satisfatório, proporcionando uma experiência gastronômica inesquecível.</p><p><br></p><p>Presente Perfeito: Não apenas um mimo para si mesmo, mas também uma ótima opção para presentear. Combinando o sabor delicioso do chocolate com a emoção de um brinquedo divertido, nosso ovo de Páscoa é o presente ideal para compartilhar a alegria desta temporada especial.</p><p><br></p><p>Celebre a Páscoa de uma maneira única e emocionante com nosso Ovo de Páscoa com Brinquedo. Disponível por tempo limitado, antecipe suas compras e nao deixe para ultima hora, então não perca a chance de tornar esta Páscoa verdadeiramente memorável!</p><p><br></p><p>Enviamos em caixa para nao danificar e pedimos apenas que antes de abri-lo, colocar na geladeira por cerca de 15 minutos pois devido a temperatura das agencias pode aquecer o chocolate.</p><p><br></p><p>Garantia do vendedor: 7 dias</p><p><br></p><p>Garantia do vendedor: 7 dias</p>', 19.99, NULL, NULL, 'https://cf.shopee.com.br/file/sg-11134201-8261e-mkiyummn7v2c20', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7345162422952085.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.1589116043710067.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.2726485529732041.webp}', NULL, 'D&G PROMOÇOES', 'https://s.shopee.com.br/7VBuxEXbHN', 3.9, 0, 0, true, NULL, '2026-03-24 11:54:41.610956+00', '2026-