INSERT INTO public.products VALUES ('6e60439d-bb86-4de1-a6a3-a450669e31da', 'Aparelho De Medir Pressão Arterial De Braço Visor Digital Inteligante', '<p>Características:</p><p>1. Display LED: Nosso monitor de pressão arterial é equipado com um grande display LED, que proporciona uma ótima experiência de visualização, tornando as leituras mais claras e os usuários podem ver os resultados mais rápidos. Limpar grandes fontes e uma tela retroiluminada de alta definição proporcionam leituras claras à noite para uma experiência avançada de medição.</p><p>2. Maior precisão: O monitor automático de pressão arterial tem tecnologia de medição avançada para fornecer as leituras mais precisas. Conveniente para rastrear sua saúde diária.</p><p>3. Operação de um botão: A máquina de pressão arterial é totalmente automática, você só precisa pressionar o botão "Start" para medir sua pressão arterial e frequência cardíaca. Todo o processo leva apenas meio minuto. O design amigável do usuário pode ser adequado para a maioria das pessoas, mesmo os usuários sêniores podem operar se forem sem esforço por si mesmos, sem necessidade da orientação dos outros.</p><p>4. Detecção de arritmia: monitores de pressão arterial são sensíveis o suficiente para rastrear mau funcionamento do batimento cardíaco que você pode não ter notado. Isso disse, medindo estresse, você também pode verificar sua frequência cardíaca.</p><p>5. Grande capacidade de armazenamento: 99 medidas permitem que você saiba sua pressão arterial a qualquer momento. Compare as leituras dos últimos dias para que você possa dar passos para evitar surpresas desagradáveis. 3 minutos de dispositivo de economia de energia automática, depuração de equipamentos inteligentes, detecção automática.</p><p><br></p><p>Descrição:</p><p>Inteligentemente projetado para leitura fácil e clara, o punho de pressão arterial é equipado com uma tela LCD grande para leituras mais precisas em 45 segundos. O monitor automático de pressão arterial tem tecnologia de medição avançada para fornecer as leituras mais precisas. Conveniente para rastrear sua saúde diária.</p><p><br></p><p>Especificações:</p><p>Material: Plástico ABS</p><p>Tamanho: 118*98*85mm</p><p>Pressão Sangue: 20-280mmHg</p><p>Taxa cardíaca: 40-165 batidas/min</p><p>Fonte de alimentação: bateria AAA*4 (não incluída), pode usar energia CA</p><p>Pressurização: Modo de Pressurização Automática</p><p>Temperatura de Operação: 15%-90%</p><p>Umidade de Operação: 40a-r59%</p><p>Temperatura de Armazenamento: -20℃-50℃</p><p>Umidade de Armazenamento: -20℃-50℃</p><p>Pulso: 40-200 Beatsainuto</p><p>Aplicação: Pulso</p><p><br></p><p>Incluído no Pacote:</p><p>1 pc * Hematomanômetro (Unidade principal)</p><p>1 pc * Faixa de Manguito</p><p>1 pc * Manual do usuário</p><p>1pc*cabo TYPC</p>', 59.97, NULL, 22, 'https://cf.shopee.com.br/file/sg-11134201-7ra11-mba5kx8345u8b8', '{}', NULL, 'LOJA AGIL ', 'https://s.shopee.com.br/10yT98Z5BL', 4.8, 0, 0, true, NULL, '2026-03-25 16:59:26.132668+00', '2026-03-30 02:50:58.796702+00', 'f2f2e3af-9143-4a2c-9194-f6282a1cfcd6', NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, NULL, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '95a00be7-7f36-4590-a2d9-f78cd0a12689', NULL, 36, 333, '[]', NULL, '{}', '{}');
