INSERT INTO public.products VALUES ('f42ef9f7-080f-4748-8663-f310f2216b7a', 'Celular Xiaomi Poco X8 Pro 8gb Ram 256gb Rom Dual Sim 6.59 Amoled Dimensity 8500 Ultra Green', '<p>📱 POCO X8 Pro 5G – 8GB RAM | Dimensity 8500 Ultra | Tela AMOLED 120Hz | Câmera 50MP | Bateria 6500mAh</p><p><br></p><p>O novo POCO X8 Pro 5G chega trazendo tecnologia de última geração, desempenho extremo e bateria gigante para quem exige velocidade, qualidade e autonomia. Equipado com o poderoso MediaTek Dimensity 8500 Ultra, tela AMOLED ultra brilhante e carregamento super rápido de 100W, ele é perfeito para jogos, trabalho e entretenimento.</p><p><br></p><p>⚡ Desempenho poderoso</p><p>Com o processador Dimensity 8500 Ultra (4nm) e GPU Mali-G720 MC8, o POCO X8 Pro oferece alto desempenho para rodar jogos pesados, multitarefa e aplicativos exigentes com extrema fluidez.</p><p><br></p><p>-ARMAZENAMENTO INTERNO:</p><p>256GB</p><p>512GB</p><p>-RAM:</p><p>8GB</p><p>12GB</p><p>Memória de alta velocidade UFS 4.1 para carregamentos muito mais rápidos.</p><p><br></p><p>🖥️ Tela AMOLED 120Hz ultra brilhante</p><p>A tela de 6.59" AMOLED entrega imagens impressionantes com cores vibrantes e fluidez incrível.</p><p>✔ 120Hz taxa de atualização</p><p>✔ Dolby Vision + HDR10+</p><p>✔ HDR Vivid</p><p>✔ Brilho máximo de 3500 nits</p><p>✔ Resolução 1268 × 2756 (1.5K)</p><p>✔ 3840Hz PWM Dimming (mais conforto para os olhos)</p><p>Perfeita para jogos, filmes e redes sociais.</p><p><br></p><p>📸 Câmera dupla com 50MP</p><p>Capture fotos nítidas e vídeos de alta qualidade com o sistema de câmera avançado.</p><p>Câmera principal</p><p>50MP com OIS (estabilização óptica)</p><p>HDR e modo panorama</p><p>Câmera ultrawide</p><p>8MP</p><p><br></p><p>🎥 Vídeo:</p><p>4K até 60fps</p><p>Slow motion até 960fps</p><p>HDR10+</p><p><br></p><p>📷 Câmera frontal:</p><p>20MP para selfies e chamadas de vídeo em alta definição.</p><p><br></p><p>🔋 Bateria gigante + carregamento ultrarrápido</p><p>Com 6500mAh, o POCO X8 Pro oferece bateria para o dia inteiro ou mais.</p><p>⚡ Carregamento rápido de 100W</p><p><br></p><p>🔊 Som estéreo premium</p><p>Alto-falantes estéreo</p><p>Áudio Hi-Res 24bit / 192kHz</p><p>Hi-Res Wireless</p><p><br></p><p>📡 Conectividade completa</p><p>✔ 5G ultra rápido</p><p>✔ Wi-Fi 6</p><p>✔ Bluetooth 5.4</p><p>✔ NFC</p><p>✔ GPS multibanda</p><p>✔ Sensor digital na tela</p><p>✔ Infravermelho (IR Blaster)</p><p><br></p><p>💧 Resistência</p><p>Certificação IP68 / IP69K</p><p>✔ Resistência à água</p><p>✔ Resistência à poeira</p><p><br></p><p>📦 Especificações principais</p><p>Sistema: Android 16 + HyperOS 3</p><p>Tela: 6.59" AMOLED 120Hz</p><p>Processador: Dimensity 8500 Ultra</p><p>RAM: 8GB</p><p>Armazenamento: 256GB OU 512GB</p><p>Câmera: 50MP + 8MP</p><p>Selfie: 20MP</p><p>Bateria: 6500mAh</p><p>Carregamento: 100W</p><p>Rede: 5G</p><p>Dual SIM</p>', 2779, 2419, NULL, 'https://http2.mlstatic.com/D_NQ_NP_2X_619994-MLA108307143102_032026-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_619994-MLA108307143102_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_915362-MLA108307143112_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_694563-MLA108307292126_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_876006-MLA108306099744_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_676211-MLA109098787673_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_605743-MLA108307530642_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_703093-MLA109098668551_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_642593-MLA108307530658_032026-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_951689-MLA108307173188_032026-F.webp}', 'Novo', 'rbjm05', 'https://meli.la/23WvzSM', 4.8, 0, 1, true, NULL, '2026-04-01 19:47:13.502292+00', '2026-04-02 11:20:22.314224+00', '562df9b8-8a3a-419d-bce3-152b980c7927', 'a5c36a6e-033f-43a4-a4f3-2ace904ef8c7', '470eab59-13aa-43e1-84f0-71712bd56389', NULL, -14.9, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 5, 50, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('9d81f408-7e11-4ed8-9dc8-ca39ae25f4f5', 'Samsung Galaxy Tab A11+ 5g 6gb, 128gb Cinza', 'A Samsung Galaxy Tab A11+ 5G é a escolha ideal para quem busca desempenho e versatilidade em um tablet. 

Com uma tela de 11 polegadas e resolução de 1920 px x 1200 px, você poderá desfrutar de imagens nítidas e vibrantes, seja para assistir a vídeos, jogar ou trabalhar. Equipado com um processador MediaTek MT8755 de 8 núcleos e 6 GB de RAM, este dispositivo garante uma experiência fluida e rápida.

A capacidade de armazenamento de 128 GB permite que você armazene todos os seus aplicativos, fotos e vídeos sem preocupações. Além disso, a possibilidade de expandir a memória com um cartão Micro-SD de até 2 TB oferece ainda mais flexibilidade. 

A bateria de 7040 mAh proporciona horas de uso contínuo, ideal para quem está sempre em movimento.

Com conectividade 5G, Bluetooth 5.3 e Wi-Fi, você estará sempre conectado, seja em casa ou em trânsito. O tablet também conta com recursos como desbloqueio facial, giroscópio e sensor de luz ambiente, tornando-o uma ferramenta prática e moderna. 

A câmera traseira de 8 Mpx e a frontal de 5 Mpx são perfeitas para videochamadas e capturar momentos especiais.

A Samsung Galaxy Tab A11+ 5G é mais do que um tablet; é um dispositivo que se adapta ao seu estilo de vida. Seja para trabalho, estudo ou entretenimento, este tablet oferece tudo o que você precisa em um design elegante e leve, pesando apenas 477 g.

Aviso legal
