INSERT INTO public.products VALUES ('791c2ba8-8e2c-4776-984e-370cc90e5f54', 'Conjunto Kit De 6 Facas Tramontina Carnes Cozinha Suporte Cepo', '<p>Detalhes do produto:Conjunto de Facas 6 Peças Com Cepo 23498/028 Preto Plenus Tramontina</p><p> </p><p>Conjunto de Facas 6 Peças Com Cepo 23498/028 Preto Plenus Tramontina</p><p> </p><p>Você vai impressionar seus convidados com a Jogo de Facas Tramontina Plenus com Lâminas em Aço Inox Cabos de Polipropileno Preto e Suporte de Madeira 6 Peças da Linha Plenus. São cinco peças produzidas com cabos na cor preta de polipropileno e lâminas de aço inox, resistentes e fáceis de manusear, podendo ser levadas à máquina de lavar louças.</p><p><br></p><p>Versáteis e com design moderno, se encaixam em diferentes usos. Podem serem usadas desde preparações mais simples até mais elaboradas. O jogo de facas é a escolha ideal para embelezar ainda mais o seu ambiente!</p><p> </p><p>Especificações Técnicas:</p><p> </p><p>- Cor: Preto;</p><p>- Marca: Tramontina;</p><p>- Garantia: 3 meses.</p><p> </p><p>Características:</p><p> </p><p>- Lâmina de aço inox com maior durabilidade do fio devido ao tratamento térmico;</p><p>- Cabos de polipropileno com maior resistência e durabilidade;</p><p>- Suporte para facas de madeira e polipropileno;</p><p>- Podem ir à máquina de lavar louças facilitando seu dia a dia.</p><p> </p><p>Dimensões da embalagem:</p><p> </p><p>- Altura: 30 cm;</p><p>- Largura: 12,5 cm;</p><p>- Comprimento: 21,5 cm;</p><p>- Peso: 1.258.</p><p> </p><p>Itens Inclusos:</p><p> </p><p>- 1 unidade - Faca para Legumes e Frutas 3" Plenus - 18,5 cm x 2,3 cm x 1,4 cm;</p><p>- 1 unidade - Faca para Desossar 5" Plenus - 26,2 cm x 3,4 cm x 1,8 cm;</p><p>- 1 unidade - Faca Chef 7" Plenus - 29,9 cm x 4,7 cm x 1,8 cm;</p><p>- 1 unidade - Faca para Tomate 5" Plenus - 23,1 cm x 2,3 cm x 1,4 cm;</p><p>- 1 unidade - Garfo trinchante Plenus - 26,1 cm x 1,7 cm x 2,2 cm;</p><p>- 1 unidade Cepo de madeira.</p><p> </p><p>Dúvidas Frequentes:</p><p> </p><p>1. Os produtos são novos?</p><p>- Todos os nossos produtos são novos na caixa lacrados com garantia e procedência legal.</p><p> </p><p>2. O produto acompanha nota fiscal?</p><p>- Todas as mercadorias são acompanhadas com nota fiscal emitidas em seus dados informados na compra, em nenhuma hipóteses efetuamos vendas sem emissão de nota fiscal.</p><p> </p><p>3. A mercadoria está disponível à pronta entrega?</p><p>- Todas as mercadorias são para pronta entrega para envio de imediato no prazo de até 24 horas.</p><p> </p><p>4. Está com alguma duvida?</p><p>- Use o campo de perguntas para tirar todas suas duvidas, somente clica em comprar após ter certeza em concordar com as condições descritas acima.</p><p> </p><p>Informações importantes</p><p> </p><p>- As imagens são meramente ilustrativas, os objetos que ambientam as fotos não acompanham o produto.</p><p>- Pode haver alguma diferença de tonalidade entre a imagem e o produto real, por conta do tratamento de imagens e a calibração de cores do seu monitor.</p><p>- Produto para uso residencial em ambiente interno, não devendo ficar exposto diretamente ao sol, calor e umidades excessivas.</p><p>- Ao receber a mercadoria, o cliente deve verificar as condições da embalagem, caso haja alguma avaria não assine o comprovante de recebimento.</p>', 151.91, 159.9, 5, 'https://cf.shopee.com.br/file/sg-11134201-7rash-ma8v9h3focpzc8', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5430530307015042.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.2611321159676383.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7247365044099185.webp}', NULL, 'Lojas Overlar Oficial', 'https://s.shopee.com.br/BPVzEWbBb', 0, 0, 0, true, NULL, '2026-03-31 20:56:45.025026+00', '2026-04-01 20:04:25.787152+00', '1a071b94-6208-4fc3-bfa5-2fc6be200de4', '38db503d-ed96-4503-a053-97b01eabf850', '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 5.0, 'ae8dfd8c-