INSERT INTO public.products VALUES ('5ca3995f-eac6-4363-93fa-42b0c96761cf', 'Celular Xiaomi Redmi Note 15 Pro 512GB OU 256GB ', '<p>📱 Xiaomi Redmi Note 15 Pro 4G – Potência Extra, Câmeras Avançadas e Tela Premium</p><p><br></p><p>✅ Produto 100% Original Xiaomi</p><p>✅ Novo, Lacrado na Caixa</p><p>✅ Versão Global</p><p>✅ Pronta Entrega – Envio Rápido para Todo o Brasil</p><p><br></p><p>O Redmi Note 15 Pro 4G combina alto desempenho, fotografia avançada e uma tela premium AMOLED 120Hz, ideal para redes sociais, vídeos, jogos e multitarefas diárias. Com sistema Android 15 + HyperOS, ele entrega fluidez e confiabilidade em todas as tarefas. </p><p><br></p><p>⚙️ Especificações Técnicas</p><p><br></p><p>🔹 Modelo: Xiaomi Redmi Note 15 Pro 4G</p><p>🔹 Rede: 4G / LTE</p><p>🔹 Sistema Operacional: Android 15 com HyperOS</p><p>🔹 Processador: MediaTek Helio G200 Ultra</p><p>🔹 Dual SIM: Sim </p><p><br></p><p>💾 Memória &amp; Armazenamento</p><p><br></p><p>📦 Opções disponíveis (confira no seu estoque):</p><p><br></p><p>✔️ 8GB RAM + 256GB armazenamento</p><p>✔️ 8GB RAM + 512GB armazenamento</p><p><br></p><p>➡️ Armazenamento interno rápido e RAM ideal para multitarefas, apps pesados e jogos. </p><p><br></p><p>📺 Tela</p><p><br></p><p>🖥️ Tela AMOLED de 6,77” com 120Hz</p><p>🌈 Cores vibrantes, alto brilho com Gorilla Glass Victus 2 para proteção</p><p>👁️ Perfeita para vídeos, streaming e jogos com fluidez visual. </p><p><br></p><p>📸 Câmeras</p><p><br></p><p>📷 Câmera principal de 200 MP + 8 MP ultrawide + 2 MP macro</p><p>🤳 Câmera frontal de 32 MP</p><p>📸 Fotos com detalhes impressionantes e vídeos de ótima qualidade no dia a dia. </p><p><br></p><p>🔋 Bateria</p><p><br></p><p>🔋 Bateria de 6500 mAh com carregamento rápido 45 W</p><p>🔌 Bateria duradoura para um dia inteiro de uso ativo sem preocupações. </p><p><br></p><p>🌐 Conectividade &amp; Extras</p><p><br></p><p>✔️ NFC </p><p>✔️ Bluetooth</p><p>✔️ USB-C com OTG</p><p>✔️ Rádio FM</p><p>✔️ Sensores: impressão digital sob a tela, proximidade, giroscópio</p><p>✔️ Alto-falantes estéreo com Dolby Atmos</p><p>✔️ Proteção contra poeira/água (certificação conforme mercado) </p><p><br></p><p>🎨 Cores Disponíveis</p><p>✔️ Preto</p><p>✔️ Azul</p><p>✔️ Titânio (Cinza)</p><p><br></p><p>📦 Conteúdo da Embalagem</p><p><br></p><p>📱 Smartphone Redmi Note 15 Pro 4G</p><p>🔌 Carregador original</p><p>🔋 Cabo USB-C</p><p>📌 Ferramenta do SIM</p><p>📖 Manual</p><p>📦 Caixa original lacrada</p><p><br></p><p>🛡️ Garantia &amp; Segurança</p><p>✔️ Produto original Xiaomi</p><p>✔️ Envio seguro e bem embalado</p><p>✔️ Compra tranquila pela Shopee</p><p><br></p><p>🚚 Envio</p><p>📦 Postagem rápida após confirmação do pagamento</p><p>🚛 Entrega para todo o Brasil</p><p><br></p><p>💡 Ideal para quem procura:</p><p>✔️ Tela AMOLED 120Hz com excelente brilho</p><p>✔️ Câmera de 200 MP para fotos detalhadas</p><p>✔️ Bateria 6500 mAh para uso prolongado</p><p>✔️ Ótimo custo-benefício na série Pro da Xiaomi</p>', 1590.68, 1729, 8, 'https://cf.shopee.com.br/file/sg-11134201-825zo-mjh92aoo20p09a', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7335373658557995.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.2772577975895163.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7003721364175077.webp}', 'Oferta!', 'CBO COMERCIAL', 'https://s.shopee.com.br/4VYIVJGoOb', 5, 0, 1, true, NULL, '2026-03-23 22:42:11.063938+00', '2026-04-02 18:38:06.566887+00', 'c8ac1472-f7ac-46fe-9728-e0a2924d58f6', 'ba7bc42e-11d1-4bf9-b887-4b9ff4daada7', '5a54bf84-4707-4f0f-a23c-689469fdbbb7', 'br-11110105-6v65e-mk2p97mzwmbl63.16000081769706627.mp4', 8.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 4, 342, '[]', NULL, '{}', '{}');
INSERT INTO public.products VALUES ('e95ebbf1-b07a-4ea0-8cb0-6d7595380a14', 'Câmera Segurança Lâmpada Ip Wifi 360° Full HD Yoosee Inteligente Prova D''água Giratória Visão Noturna Infravermelho Detecção de Movimentos 1080P HD Bivolt Premium', '<ul><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">INSTALAÇÃO FÁCIL: Câmera de segurança em formato de lâmpada com soquete E27, permitindo instalação simples em qualquer bocal padrão</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">VISUALIZAÇÃO 360°: Sistema de rotação completa com controle via aplicativo para monitoramento em todos os ângulos</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">VISÃO NOTURNA: Equipada com 8 LEDs infravermelhos para vigilância noturna clara e eficiente</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">CONECTIVIDADE: Conexão WiFi integrada para monitoramento remoto em tempo real através do smartphone</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">RECURSOS AVANÇADOS: Detecção de movimento inteligente, gravação em 1080P HD e função à prova d''água para uso interno e externo</span></li></ul><p><br></p>', 49.9, 54.9, NULL, 'https://m.media-amazon.com/images/I/518yvWT0opL._AC_UL320_.jpg', '{https://m.media-amazon.com/images/I/518yvWT0opL._AC_UL320_.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.12693387130912792.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.09262309758533194.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.08579959079808153.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5072149651096383.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.26344094768631154.jpg}', 'Economize 9%', 'Amazon Brasil', 'https://amzn.to/4dhSP2t', 4.5, 0, 0, true, NULL, '2026-03-29 17:47:07.79063+00', '2026-03-29 17:49:33.74933