INSERT INTO public.products VALUES ('31307eba-7a77-4c87-bd8c-f631efafe659', 'Power Stay Batom Líquido Matte 16h', '<p>Por que escolher o Power Stay Batom Líquido Matte 16H?</p><p>• Até 16h de duração com acabamento matte aveludado.</p><p>• Nova fórmula mais confortável com Complexo Power Boost (Óleo de Oliva e Extrato de Romã).</p><p>• Tecnologia Color Lock: não transfere, não borra e não desbota.</p><p>• Tecnologia Power Flex: sensação flexível, não craquela e não deixa os lábios pegajosos.</p><p>• Aplicador anatômico com ponta diamante para contorno e preenchimento precisos.</p><p>• Alta pigmentação e cobertura total em uma só passada.</p>', 29.99, 49.99, 40, 'https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-avon-br-storefront-catalog/default/dwaf62b873/produtos/135563.jpg?sw=300&q=80', '{https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-avon-br-storefront-catalog/default/dwaf62b873/produtos/135563.jpg?sw=300&q=80}', '40% OFF', 'Avon', 'https://minhaloja.natura.com/p/batom-liquido-matte-power-stay-vermelhaco-7-ml/AVNBRA-135563?position=2&listTitle=search+results+list+showcase+-+Power+Stay+Batom+L%C3%ADquido+Matte+16h&consultoria=ofertashop&marca=avon', 5, 0, 1, true, NULL, '2026-03-29 01:35:10.464976+00', '2026-03-29 23:56:47.000063+00', '8de9e1dd-181c-49da-bba8-6ab7bd1cab6e', 'fb13a177-3298-4ee8-a145-a495ded2387f', 'de272181-2746-452b-9889-0010ef316521', NULL, 40.0, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '95a00be7-7f36-4590-a2d9-f78cd0a12689', 'AVNBRA-135563', NULL, 0, NULL, NULL, '{"shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('06fb4685-aa22-4c2f-ba13-34a96966dcee', 'Cafeteira Espresso Eos 2 em 1 Italiana com 20 Bar de Pressão Inox Ecf06ec 110v', '<p>Cafeteira Espresso EOS 2 em 1 Italiana com 20 Bar de Pressão Inox ECF06EC</p><p><br></p><p>Cafeteira Espresso EOS 2 em 1 Italiana Inox ECF06EC</p><p><br></p><p>Para quem valoriza um bom café logo cedo ou ao longo do dia, a Cafeteira Espresso EOS 2 em 1 oferece qualidade profissional na sua cozinha. Compacta e eficiente, conta com bomba de alta pressão de 20 BAR, garantindo extração intensa, com sabor e aroma marcantes.</p><p><br></p><p>Ideal também para cappuccinos e lattes, vem com espumador de leite integrado, que proporciona espuma cremosa na temperatura certa. Seu design moderno em inox combina com qualquer ambiente e traz sofisticação ao preparo.</p><p><br></p><p>Além do desempenho, é fácil de usar e limpar, com controles intuitivos e peças removíveis que facilitam o dia a dia.</p><p><br></p><p>Principais vantagens:</p><p><br></p><p>Prepara cafés encorpados e aromáticos com extração profissional</p><p><br></p><p>Espumador de leite para bebidas cremosas como cappuccino e latte</p><p><br></p><p>Design moderno em inox, compacto e elegante</p><p><br></p><p>Bomba de 20 BAR que preserva o creme e aquece na medida certa</p><p><br></p><p>Fácil operação e limpeza prática</p>', 419.91, 554.44, NULL, 'https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/1774982726594-5ncyzyin3fk.jpg', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.13172100058262104.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5171557109127042.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7165146705978513.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5350965661576815.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.95632658