INSERT INTO public.products VALUES ('edf9978e-b466-4ac5-9a59-7e2a79ca0ad4', 'Mini Projetor Smart Portátil Hy300 4k Android Bluetooth 110v Branco 127/220v', '<p>Descrição do produto</p><p>Mini Projetor Wifi Portátil 5G Android'' é a solução que vai transformar sua forma de curtir filmes, jogos e apresentações. Projetor e Smart Tv no mesmo aparelho.</p><p><br></p><p>PRINCIPAIS BENEFÍCIOS</p><p><br></p><p>- Espelhamento de celular: feito através de aplicativos que você baixa tanto no projetor quanto no seu smartphone.</p><p><br></p><p>- Conexão Sem Fio 5G: A conectividade 5G oferece uma experiência de streaming e navegação mais rápida e estável.</p><p><br></p><p>- Entretenimento Ampliado: Proporciona uma experiência de entretenimento ampliada ao transformar qualquer ambiente em uma tela grande para filmes, séries, jogos, vídeos, fotos, trabalhos, etc.</p><p><br></p><p>- Apresentações Flexíveis: Ideal para apresentações de negócios ou educacionais, eliminando a necessidade de cabos e facilitando a configuração.</p><p><br></p><p>- Compatibilidade Versátil: Pode ser conectado a vários dispositivos, como laptops, smartphones, tablets e consoles de vídeo games, ampliando suas opções de uso.</p><p><br></p><p>- Qualidade de Imagem: Oferece imagens de alta qualidade e resolução, garantindo uma experiência visual nítida e vívida.</p><p><br></p><p>- Conveniência: Simplifica a exibição de conteúdo de mídia e a navegação na web em uma tela maior, tornando o acesso a informações e entretenimento mais prático.</p><p><br></p><p>DIFERENCIAIS</p><p><br></p><p>- Flexibilidade de Localização: Oferece flexibilidade na escolha do local para projeção, sem a necessidade de cabos longos.</p><p><br></p><p>- Qualidade de Imagem: Fornece imagens nítidas e de alta qualidade, mesmo em telas menores, proporcionando uma experiência de visualização aprimorada.</p><p><br></p><p>- Acesso à Internet: A conectividade 5G integrada permite o acesso à internet de alta velocidade para streaming e navegação online.</p><p><br></p><p>- Portabilidade: Sua natureza compacta e portátil torna-o conveniente para viagens, acampamentos e uso em diferentes ambientes.</p><p><br></p><p>PRINCIPAIS FUNÇÕES</p><p><br></p><p>- Espelhamento de Celular.</p><p><br></p><p>- 8G de memória interna para instalar Apps diversos.</p><p><br></p><p>- Com entrada USB: você pode reproduzir arquivos diretamente de dispositivos de armazenamento como Pendrive ou HDs.</p><p><br></p><p>- Articulado 180°: permite projeções em qualquer ângulo, até no teto do ambiente.</p><p><br></p><p>- Com lâmpada LED de alta qualidade.</p><p><br></p><p>- Resolução 720P HDR, a imagem é surpreendente.</p><p><br></p><p>- Conectividade Bluetooth: Com Bluetooth 5.2, você pode conectar dispositivos facilmente.</p><p><br></p><p>- Ajuste Automático de Imagem: A imagem é autoajustável para uma experiência perfeita.</p><p><br></p><p>ESPECIFICAÇÕES TÉCNICAS</p><p><br></p><p>- Sistema Operacional: Android</p><p><br></p><p>- Idioma: Português (e vários outros a sua escolha).</p><p><br></p><p>- Memória interna: 8Gb</p><p><br></p><p>- Resolução: 720P HDR.</p><p><br></p><p>- Conexões: Wifi (2.4G e 5G), Bluetooth, USB, HDMI.</p><p><br></p><p>- Lúmens: 12000ansi</p><p><br></p><p>- Compatibilidade de Smartphones: Android e iOS.</p><p><br></p><p>- Dimensões: 19 x 9,5 cm.</p><p><br></p><p>- Peso: 650g.</p><p><br></p><p>- Alimentação: 110V~220V (bivolt).</p><p><br></p><p>- Ajuste de foco.</p><p><br></p><p>- Alto falante embutido.</p><p><br></p><p>- Saída de áudio Auxiliar</p><p><br></p><p>ITENS INCLUSOS</p><p><br></p><p>1x Mini Projetor Wifi Portátil 5G.</p><p><br></p><p>1x Cabo de energia.</p><p><br></p><p>1x Manual de instruções para uma configuração rápida.</p><p><br></p><p>1x Controle Remoto.</p>', 164.35, 173, 5, 'https://cf.shopee.com.br/file/br-11134207-81z1k-mhw8z67vb40119', '{}', NULL, 'AQShopping', 'https://s.shopee.com.br/7KsYz80UtF', 4.9, 0, 1, true, NULL, '2026-03-27 03:32:43.673301+00', '2026-03-27 15:31:26.131306+00', 'f2f2e3af-9143-4a2c-9194-f6282a1cfcd6', 'ca980684-198c-4763-8b98-ca8053b840c9', '5a54bf84-4707-4f0f-a23c-689469fdbbb7', 'https://www.youtube.com/shorts/D5Yfjguu5lQ', 5.0, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 3, 787, '[]', NULL, '{"price_analysis": {"verdict": "O preço atual é o melhor encontrado e oferece um desconto real.", "savings_tip": "Fique de olho em cupons adicionais ou eventos de frete grátis para aumentar a economia.", "is_good_deal": true, "published_at": "2026-03-27T07:29:40.557Z", "best_platform": "Shopee", "recommendation": "Não há outras plataformas com preço inferior; vale a pena comprar agora na Shopee. Aproveite o desconto de aproximadamente 5% sobre o preço de referência."}}', '{}');
