INSERT INTO public.products VALUES ('b62b2e31-1d8c-4ab0-b9b5-722b43ad75d3', 'Sabonete em Barra Puro Vegetal Tododia Romã e Flor de Amora', '<p>Limpa sem ressecar e perfuma a pele com a fragrância envolvente de Romã e Flor de Amora.</p><p><br></p><p>Viva um banho cheio de sentidos com o Sabonete em Barra Puro Vegetal Tododia Romã e Flor de Amora. Sua fórmula gentil envolve uma cuidadosa combinação de ingredientes de origem natural que mantém a hidratação da sua pele e a deixa perfumada.</p>', 26.1, 34.9, 25, 'https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/1774388379220-o45sfsjrz6.jpeg', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.007576596784928169.webp}', 'Muito Barato', 'Natura', 'https://sminhaloja.natura.com/memkRUw', 0, 0, 5, true, NULL, '2026-03-24 21:42:21.24471+00', '2026-03-26 19:34:00.491538+00', 'abbed348-d0b2-42d9-a2a9-ff8c1ec9f689', '5cbe6e44-319e-40d3-8f78-e32d09234a7a', 'f729f5cd-3b0a-4ded-88d8-a5b578f0fb0b', NULL, 25.2, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '95a00be7-7f36-4590-a2d9-f78cd0a12689', NULL, NULL, 0, '[]', NULL, '{}', '{}');
INSERT INTO public.products VALUES ('bebbe3c7-58a6-4dd0-9e52-76d918dd0a41', 'Kit 8 Alimentação Bebê Silicone Prato Babador Copo Tigela Cor Azul-aço', 'Este conjunto de 8 peças de pratos com ventosa infantil é feito de silicone de alta qualidade, livre de BPA, garantindo segurança durante as refeições. O babador de silicone é macio, e os outros utensílios, como tigelas, pratos, garfos e colheres, são resistentes a quedas.

A textura antiderrapante do silicone incentiva os bebês a comerem de forma independente, evitando respingos e bagunças. É perfeito para uso diário, resistindo ao desgaste e ao uso constante.

Compacto e leve, é ideal para viagens, camping, piqueniques e jantares em família. Seu tamanho moderado se adapta à maioria das mesas e cadeiras infantis, facilitando o transporte.

Além disso, pode ser usado no micro-ondas e na geladeira, mantendo a comida na temperatura certa. Este conjunto completo de talheres é um presente significativo para novos pais.

Especificações:

Cores disponíveis: azul, rosa
Material: silicone de qualidade alimentar (BPA free)
Tamanhos: prato (19x18.2 cm), babador (24x29.5 cm), tigela (11.2x11 cm), colher (13.5 x 3.5 cm), copo de água (14 x 14 cm)
Faixa etária: acima de 3 meses
O pacote inclui:

1 prato de silicone
1 tigela
1 colher e 1 garfo com cabo de madeira
1 colher e 1 garfo em silicone
1 babador
1 copo de água com tampa canudo.', 36.24, NULL, NULL, 'https://http2.mlstatic.com/D_NQ_NP_2X_908926-MLA99598913234_122025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_908926-MLA99598913234_122025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_619917-MLA91512913510_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_612686-MLA91513459236_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_955038-MLA91911660313_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_935499-MLA91512933554_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_765762-MLA91513489110_092025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_948849-MLA91911214269_092025-F.webp}', 'Novo', 'maiscomprasrj Vendido porGCTECOMM Vendido porMRGIFTS', 'https://meli.la/2JL5KEQ', 4.8, 0, 2, true, NULL, '2026-03-24 12:50:20.030835+00', '2026-03-28 19:50:06.726215+00', NULL, NULL, '470eab59-13aa-43e1-84f0-71712bd56389', NULL, NULL, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', 'd1baff6d-2ffd-4dba-be65-17296065b247', NULL, 12, 10000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('d96a9913-c1fd-422b-b617-0f363188ff71', 'KIT 50 CABIDES DE VELUDO ANTIDESLIZANTE PREMIUM FUKUYAMA Com Gancho Giratório 360° ESCOLHA A COR', 'Cabide Aveludado ADULTO MARCA: FUKUYAMA®
Sofisticação, Praticidade e Qualidade Japonesa para Seu Guarda-Roupa
Transforme o seu guarda-roupa com os Cabides Aveludado FUKUYAMA®. A escolha perfeita para quem valoriza organização, elegância e a qualidade excepcional da marca japonesa FUKUYAMA. Conhecida pela sua dedicação à excelência e à atenção aos detalhes, a FUKUYAMA traz para você um cabide que combina funcionalidade e sofisticação.
O cabide aveludado FUKUYAMA® possui um revestimento suave e delicado, que impede que suas roupas deslizem ou se deformem, proporcionando a máxima proteção para suas peças. Sua superfície de veludo preserva o formato original de camisas, vestidos, blusas de seda e outras roupas delicadas, enquanto mantém o seu guarda-roupa mais organizado e elegante.
Por que escolher o Cabide Aveludado FUKUYAMA?
Qualidade Japonesa: A FUKUYAMA® é reconhecida mundialmente pela sua precisão e excelência, características que se refletem em cada detalhe deste cabide.
Antideslizante: O revestimento aveludado mantém suas roupas no lugar, sem riscos de escorregarem ou se amassarem.
Cuidado com as Peças: Ideal para roupas mais delicadas, prevenindo deformações e marcas.
Design Elegante e Funcional: O cabide FUKUYAMA® é fino e discreto, otimizando o espaço do seu armário sem perder o charme.
Durabilidade: Feito para durar, com materiais de alta resistência e acabamento impecável.
Experimente a qualidade e a tradição japonesa com o cabide aveludado FUKUYAMA® e traga mais organização e sofisticação para o seu closet. Aproveite e adquira o seu agora mesmo!

ESPECIFICAÇÕES: 
Tamanho:  Largura 44 cm x Altura 22,5 cm 
Materiais do cabide : plástico ABS  aveludado
Material da haste: aço cromado
CUIDADOS IMPORTANTES:
Para manter seu cabide em perfeitas condições ao longo do uso, eles devem ser limpos a seco para não danificar o material.', 59.69, 64.98, NULL, 'https://cf.shopee.com.br/file/br-11134207-820mb-ml9p6oh4zz0m9a', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.9290507015306901.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.09166009225412997.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.1482282314630481.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7931266993091455.webp}', NULL, 'Land Importações', 'https://s.shopee.com.br/7pp0WCWjLe', 4.9, 0, 0, true, NULL, '2026-04-03 00:08:18.453433+00', '2026-04-03 00:11:09.069238+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 8.1, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 3, 4843, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 22098683403, "shopee_shopid": 383184218}', '{}');
