INSERT INTO public.products VALUES ('8ec39689-5943-49d4-a09c-2c15c00bf6c1', 'Perfume Capilar + Body Splash Barbour''s Beauty Feminino Delight', 'Kit Delight – Body Splash 200ml + Perfume Capilar 50ml

