INSERT INTO public.products VALUES ('d08b73ef-666c-4010-9d77-2fe3bd860c03', 'Mesa de jogos com prateleira, carbono anti-riscos, mesa para transmissão ao vivo, mesa para PC', '<p>💕Dimensões💕</p><p><br></p><p>👍80 cm x 60 cm x 74 cm (C x L x A)</p><p><br></p><p>💕Cor💕</p><p><br></p><p>👍Branco</p><p><br></p><p>👍Preto</p><p><br></p><p>👍[Características]:</p><p><br></p><p>✅Detalhes determinam a qualidade: placa espessada de 16 mm, tampo da mesa alargado de 60 cm, porta USB (dois furos no tampo da mesa)</p><p><br></p><p>✅Estrutura/Suporte: Três tubos de 1,5 cm de espessura</p><p><br></p><p>✅Design ergonômico, confortável para longos períodos sentado</p><p><br></p><p>✅Resistente a altas temperaturas, resistente ao desgaste e fácil de limpar</p><p><br></p><p>✅Barra transversal robusta e pernas em formato de K para excelente estabilidade</p><p><br></p><p>✅Suporta facilmente 4 adultos sem balançar</p><p><br></p><p>✅Material: Painel de partículas de madeira maciça com película protetora de resina</p><p><br></p><p>✅Estável, estável, liso e bonito, resistente à ferrugem e durável!</p><p><br></p><p>✅Impermeável, resistente à corrosão e ao desgaste. A nova bancada possui um acabamento liso e delicado, com bordas de 2 mm de espessura que resistem à deformação.</p><p><br></p><p>👇👇👇Vantagens do Produto:</p><p><br></p><p>✅ Ecologicamente correto e saudável, não sujeito a deformações.</p><p><br></p><p>✅ Estável e resistente à pressão, não sujeito a quebras.</p><p><br></p><p>✅ Tubo de aço refinado, estável e durável.</p><p><br></p><p>✅ Resistente a arranhões e ao desgaste, fácil de limpar.</p><p><br></p><p>✅ Vedação de bordas meticulosa e acabamento requintado, seguro e bonito, evitando ferimentos acidentais por impacto.</p><p><br></p><p>✅ Fácil instalação, apenas alguns parafusos são necessários e uma pessoa pode concluir a instalação.</p><p><br></p><p>✅ Conexões de hardware de alta qualidade, duráveis.</p><p><br></p><p>✅ Tubo de aço de alta qualidade, estrutura estável, fino e liso, com forte capacidade de carga.</p>', 341.05, 359, NULL, 'https://cf.shopee.com.br/file/br-11134207-81z1k-mi1efkg8f2teab', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.41408949200090817.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.15082146715327993.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.4955008264023111.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.9773642581162625.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.457674258286364.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.37753819661288124.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.4563214040190653.webp}', NULL, 'Shopee', 'https://s.shopee.com.br/1BI6NeR4Tf', 4.9, 0, 0, true, NULL, '2026-04-02 21:10:11.597631+00', '2026-04-02 23:04:44.785612+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 5.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 18, 19, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 58251675404, "shopee_shopid": 1542208881}', '{"latest": {"feed": {"legendas": ["A mesa gamer que esta bombando no TikTok! Design premium e organizacao total. Corre que o estoque voa! 🔥 Link na bio. #mesagamer #setupgamer #streamer #tecnologia #ofertashop #gamer #pcgamer #imperdivel", "Transmissao ao vivo sem bagunca! Prateleira integrada, superficie ampla e anti-riscos. Seu setup completo chegou! 👇 Comente QUERO que eu envio o link! #mesadepc #gaming #ergonomia #desconto #shopee #promocao #jogos #game", "De R$ 359,00 por R$ 341,05! Aproveite o desconto antes que acabe. Frete gratis para todo Brasil! 🚀 Link na bio. #promocao #imperdivel #mesacomprateleira #jogos #ofertadodia #gamer #tecnologia #desconto"]}, "reels": {"cenas": [{"cena": 1, "audio": "Som de clique moder