INSERT INTO public.products VALUES ('e51fcd9c-831d-4e67-8fb5-ce0204ccd3bb', 'Bainha Mágica Instantanea Dupla Face (Fita Termocolante) Diversos Tamanhos!', '<p>Faça a bainha de roupas sem costurar.</p><p>Dispensa linha e agulha, não solta ao lavar.</p><p>Pode ser usado em cortinas, vestidos, calças, saias, bermudas etc.</p><p>Aplicável com ferro quente ,possui cola dos 2 lados</p><p><br></p><p>*Escolha a largura e o comprimento ideal*</p><p><br></p><p>MODO DE USAR</p><p><br></p><p>CORTE A FITA NO MESMO COMPRIMENTO DOS TECIDOS QUE VOCÊ VAI COLAR, COLOQUE ESSE PEDAÇO DE FITA ENTRE OS DOIS TECIDOS QUE DESEJA COLAR, (ESSE PROCESSO PODE SER FEITO ENTRE TECIDOS DIFERENTES OU TECIDOS IGUAIS NO CASO DE FAZER BARRA EM CALÇAS CORTINAS ETC, DOBRANDO O MESMO TECIDO POR EXEMPLO) NÃO DEIXE RUGAS PARA OBTER UM MELHOR ACABAMENTO COLOQUE O FERRO DE PASSAR ROUPAS BEM QUENTE NA EXTREMIDADE COM A FITA NO MEIO ENTRE OS DOIS TECIDOS ASSIM UMA FACE VAI COLAR NA OUTRA.</p>', 13.49, 21.83, NULL, 'https://cf.shopee.com.br/file/br-11134207-81z1k-meyneap7ixaca7', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.616290197755855.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7356009678230047.webp}', NULL, 'SHOPCASTELLO', 'https://s.shopee.com.br/7AZJZ5jeAo', 4.8, 0, 0, true, NULL, '2026-04-02 21:43:28.213206+00', '2026-04-02 21:45:50.368912+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', 'br-11110105-6v5dk-meypwsprk1l25c.16000081758569390.mp4', 38.2, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 11, 5330, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 22998924968, "shopee_shopid": 1443345147}', '{}');
INSERT INTO public.products VALUES ('c0fc85ce-20f0-4ca2-87fc-035992a27bd3', 'Creatina Pura 1kg Dark Lab Monohidratada 100% de Pureza, Sem Sabor', 'FORÇA MÁXIMA: Creatina monohidratada com 100% de pureza que aumenta força, resistência e explosão muscular para treinos de alta intensidade
