INSERT INTO public.products VALUES ('8e10d48e-849f-46c2-9457-fb7369e28706', 'Echo Dot (Geração mais recente) | Smart speaker com Alexa, som vibrante e potente, Wi-Fi e Bluetooth | Cor Branca', 'SOM VIBRANTE E POTENTE - Experimente um áudio aprimorado — vocais mais nítidos, graves mais potentes — para uma experiência Echo Dot ainda mais imersiva.
SUAS MÚSICAS E CONTEÚDOS FAVORITOS - Reproduza músicas e podcasts do Amazon Music, Apple Music, Spotify, entre outros, ou por Bluetooth em todos os ambientes da sua casa.
SEMPRE DISPONÍVEL PARA AJUDAR - Pergunte a previsão do tempo para Alexa, defina timers com sua voz, obtenha respostas e ouça piadas. Precisa de mais uns minutinhos de sono pela manhã? É só tocar no seu Echo Dot para adiar o alarme.
MAIS CONFORTO EM CASA - Controle dispositivos de casa inteligente compatíveis por voz ou com rotinas ativadas por sensores de temperatura internos. Crie rotinas para ligar o ar condicionado se a temperatura interna estiver mais quente que o ideal.
DESENVOLVIDO PARA PROTEGER A SUA PRIVACIDADE - A Amazon não vende informações pessoais de clientes. O Echo Dot foi construído com várias camadas de controles de privacidade, incluindo o botão de desligar o microfone.
APROVEITE AO MÁXIMO O PAREAMENTO DE DISPOSITIVOS - Escute música na casa toda usando os dispositivos Echo compatíveis em cômodos diferentes ou crie um sistema de home theater com o Fire TV.', 400, 459, 13, 'https://m.media-amazon.com/images/I/61aCuWauwBL._AC_SL1000_.jpg', '{https://m.media-amazon.com/images/I/61aCuWauwBL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/71YVBa7zc5L._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/714sfYxbcaL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/51EkhvTiC+L._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/61HdGRY5wqL._AC_SL1000_.jpg}', NULL, 'Amazon', 'https://amzn.to/4bPQtFS', 4.8, 0, 1, true, NULL, '2026-03-26 15:51:33.054562+00', '2026-03-27 20:12:44.584311+00', 'ef395dcf-cccc-4966-938e-0aa7d16f6d0f', NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 12.9, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', 'B09B8XVSDP', 9.5, 1000, NULL, NULL, '{"prime": false, "social_copy": {"model": "nvidia/nemotron-3-super-120b-a12b:free", "content": {"reels_hook": "🔊 Echo Dot: som potente e Alexa pronta!", "whatsapp_message": "🔊 Echo Dot nova geração com 11% OFF!\nSom potente, Alexa sempre ao seu lado.\n⏳ Por tempo limitado + últimas unidades! Corre 👉 https://amzn.to/4bPQtFS", "instagram_captions": ["🔊 Echo Dot nova geração: som potente, Alexa pronta pra te ajudar! Aproveite 11% OFF por tempo limitado! 🚀 #EchoDot #Alexa #SmartSpeaker #Oferta #Desconto #Tecnologia #CasaInteligente https://amzn.to/4bPQtFS", "🎧 Transforme seu quarto em um estúdio com o Echo Dot! Som vibrante, graves potentes e Alexa sempre ao lado. Só hoje com 11% de desconto! Últimas unidades! 🔥 #Oferta #Desconto #EchoDot #Alexa #SmartHome #Música #Gadgets https://amzn.to/4bPQtFS", "🚀 Não perca! Echo Dot com Alexa, som premium e conexão Bluetooth. Desconto de 11% + frete grátis! Corre que acaba rápido! 👇 #Oferta #Desconto #EchoDot #Alexa #Tech #SmartSpeaker #Promoção https://amzn.to/4bPQtFS"]}, "generated_at": "2026-03-27T07:26:51.587Z"}, "price_analysis": {"verdict": "O preço atual com cerca de 11% de desconto é uma oferta razoável.", "savings_tip": "Aproveite o desconto e fique atento a eventos de relâmpago ou cupons para aumentar a economia.", "is_good_deal": true, "published_at": "2026-03-27T07:27:49.288Z", "best_platform": "Amazon", "recommendation": "Não foram encontrados preços menores em outras plataformas; comprar agora na Amazon é a melhor opção disponível."}, "shipping_details": "Entrega GRÁTIS: Amanhã, 27 de Março Amanhã, 27 de Março"}', '{}');
INSERT INTO public.products VALUES ('2b2649bf-137c-4614-b2ed-9e7879872492', 'JBL, Fone de Ouvido On ear, Headphone, Tune 520BT, Sem Fio - Preto', 'PODEROSO PURE BASS. O JBL Tune 520BT apresenta o renomado som JBL Pure Bass, o mesmo que toca nos locais mais famosos em todo o mundo.
TECNOLOGIA BLUETOOTH. Transmita sem fio som de alta qualidade de seu smartphone sem cabos bagunçados com a ajuda da mais recente tecnologia Bluetooth.
PERSONALIZE SUA MÚSICA. Baixe o aplicativo gratuito JBL Headphones para personalizar o som de acordo com o seu gosto com o EQ. Os comandos de voz em seu idioma guiam você pelos recursos do Tune 520BT.
ATÉ 57 HORAS DE BATERIA. Ouça suas músicas preferidas sem fio por até 57 horas, e recarregue a bateria completa com 2 horas. Você pode obter 3 horas de música adicionais com uma carga rápida de 5 minutos.
LEVE E CONFORTÁVEL. O material leve e compacto proporcionam um uso confortável no seu dia a dia, com seu design dobrável é possível levar seu fone para qualquer lugar, dentro de uma mala de viagem ou uma mochila.', 199, 299, 40, 'https://m.media-amazon.com/images/I/51olNZRjn+L._AC_SL1500_.jpg', '{https://m.media-amazon.com/images/I/51olNZRjn+L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61sEBNIts8L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71IHCVFb1vL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61IEx-7XC3L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/615mvQ5fvhL._AC_SL1500_.jpg}', NULL, 'JBL', 'https://amzn.to/3Npu0r2', 5, 0, 2, true, NULL, '2026-03-26 15:48:53.711203+00', '2026-03-27 07:13:24.793913+00', NULL, NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 33.4, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', 'B0C3V5X3QT', 8, NULL, '[{"name": "Marca", "value": "JBL"}, {"name": "Cor", "value": "Preto"}, {"name": "Colocação na orelha", "value": "Extra-auriculares"}, {"name": "Fator de forma dos fones de ouvido", "value": "Extra-auriculares"}, {"name": "Impedância", "value": "32 Ohms"}]', NULL, '{"prime": false, "shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('6ca89580-baee-47a1-8ef0-890843531fe2', 'Presente Dia das Mães Natura Essencial Clássico', '<p>Para as mães que amam a potência de uma perfumação abundante.</p><p><strong>•</strong>&nbsp;um sofisticado&nbsp;<strong>buquê floral</strong>&nbsp;de jasmin e violeta</p><p><strong>•</strong>&nbsp;com pitanga na composição, ingrediente da&nbsp;<strong>biodiversidade brasileira</strong></p><p><strong>•</strong>&nbsp;o&nbsp;<strong>floral intenso e amadeirado do deo parfum</strong>&nbsp;revela uma fragrância marcante e refinada</p><p><strong>•</strong>&nbsp;já o&nbsp;<strong>desodorante corporal potencializa a perfumação</strong>&nbsp;e protege contra odores da transpiração</p><p><strong>•</strong>&nbsp;um presente para transbordar elegância e sofisticação.</p><p>&nbsp;</p><p><strong>contém:</strong></p><p>1 deo parfum feminino 100 ml</p><p>1 desodorante corporal feminino 100 ml</p><p>1 caixa G especial Dia das Mães</p>', 229.9, 352.8, 35, 'https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/1774304870268-zsvtjej1q8.jpeg', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.1906356219702663.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.4565933991985949.webp}', NULL, 'Natura', 'https://www.minhaloja.natura.com/p/presente-dia-das-maes-natura-essencial-classico/NATBRA-238433?position=7&listTitle=manual+showcase+-++&consultoria=ofertashop&marca=natura', 0, 0, 1, true, NULL, '2026-03-23 22:30:27.364116+00', '2026-03-29 01:32:03.937233+00', 'abbed348-d0b2-42d9-a2a9-ff8c1ec9f689', NULL, 'f729f5cd-3b0a-4ded-88d8-a5b578f0fb0b', NULL, 34.8, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '95a00be7-7f36-4590-a2d9-f78cd0a12689', NULL, NULL, 0, '[]', NULL, '{}', '{}');
