INSERT INTO public.products VALUES ('854666ec-2a9c-469a-abf2-90da03304e86', 'Smartwatch Samsung Galaxy Fit3 Display 1.6" Grafite', 'Para começar a usar o Galaxy Fit3, uma conta Samsung deve estar cadastrada em seu celular. Seus dados de saúde no seu Galaxy Fit3 serão transferidos com segurança e armazenados na Samsung Cloud conectada à sua conta, para que você possa acessar e gerenciar totalmente seus dados.
Quando a bateria estiver completamente descarregada, o Fit não ligará. Carregue totalmente o bateria antes de ligar o Fit.
A tela sensível ao toque pode funcionar mal em condições úmidas ou quando exposta à água.', 294, 599, 51, 'https://m.media-amazon.com/images/I/51bjAlTBzZL._AC_SL1000_.jpg', '{https://m.media-amazon.com/images/I/51bjAlTBzZL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/51PDb6meDaL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/61iDPAYyN8L._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/618XpoF1MBL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/61FzO3l2yeL._AC_SL1000_.jpg}', NULL, 'Samsung', 'https://amzn.to/4tcXEyN', 5, 0, 0, true, NULL, '2026-03-26 22:22:22.381254+00', '2026-03-29 00:51:36.074391+00', '73fc119a-b8cb-4e2a-b3e2-c42abc9ce67c', NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 50.9, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', 'B0CVCLGV1W', 8, 3000, '[{"name": "Características especiais", "value": "Leve"}, {"name": "Capacidade da bateria", "value": "3000 Milliamp Hours"}, {"name": "Tecnologia de conectividade", "value": "Bluetooth, Wi-Fi"}, {"name": "Padrão de comunicação sem fio", "value": "Bluetooth"}, {"name": "Composição das células da bateria", "value": "Íon-lítio"}]', NULL, '{"prime": false, "shipping_details": "Entrega GRÁTIS: Amanhã, 27 de Março. Se pedir dentro de 4 hrs 7 mins Amanhã, 27 de Março4 hrs 7 mins Entrega GRÁTIS: Segunda-feira, 30 de Março. Se pedir dentro de 9 hrs 52 mins Segunda-feira, 30 de Março9 hrs 52 mins"}', '{}');
INSERT INTO public.products VALUES ('d2eb75e2-53bf-45dc-877b-e4c96132b43d', 'Secador de Cabelo Profissional com Secagem Rápida Tecnologia Iônica, Bicos Inclusos – 110V – Cor: Rosa – Modelo Médio', 'Secagem rápida e eficiente – Ideal para todos os tipos de cabelo, reduzindo o tempo de secagem com ar potente e controlado.
Tecnologia iônica que reduz frizz e volume – Deixa os fios mais lisos, brilhantes e saudáveis após cada uso.
4 níveis de temperatura e 3 velocidades ajustáveis – Adapta-se a diferentes texturas e necessidades de finalização.
