INSERT INTO public.products VALUES ('05d07ab2-1055-4739-975b-41550773ebc5', '3 Pares Unissex Original Apertos De Levantamento De Peso Ginásio Para Proteção Palma Da Mão Exercício Sem Dedos', '1 par unissex apertos de elevação de peso Original academia academia apertos almofadas para proteção de palma sem dedos exercícios ferramentas de musculação

