INSERT INTO public.products VALUES ('0ce36686-2e92-48f1-be3f-1acb69456e6e', 'Caixa de Som JBL Grip 16W RMS IP68 - Preto', 'A JBL Grip é a caixa de som compacta criada para acompanhar qualquer momento com potência e praticidade.

SOM JBL PRO
Compacta, com graves marcantes e agudos nítidos, a JBL Grip entrega som potente otimizado em tempo real pela tecnologia AI Sound Boost, garantindo menos distorção mesmo em volumes elevados.

POTÊNCIA E BATERIA
Driver de 43 x 80 mm com 16 W RMS e até 14 horas de reprodução com Playtime Boost, proporcionando música sem interrupções em qualquer ocasião.

ATMOSFERA PERSONALIZÁVEL
Luz ambiente integrada com temas e cores ajustáveis via JBL Portable app, criando o clima ideal para cada momento.

CONECTIVIDADE
Compatível com Auracast™, permitindo parear duas ou múltiplas caixas JBL para som estéreo ou sincronizado em festas e reuniões.

RESISTÊNCIA COMPROVADA
Classificação IP68 à prova d’água, poeira e quedas de até 1 metro, perfeita para uso ao ar livre sem preocupações.

A JBL destaca-se com áudio de alta qualidade, tecnologia avançada e design moderno, proporcionando momentos únicos na vida das pessoas.

Aviso legal
• A duração da bateria depende do uso que se dê ao produto.', 454.38, 559, 22, 'https://http2.mlstatic.com/D_NQ_NP_2X_991521-MLA99990481703_112025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_991521-MLA99990481703_112025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_775785-MLA94808098839_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_799080-MLA94807881997_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_719057-MLA94378128660_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_853414-MLA94808178341_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_609516-MLA94807813465_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_625068-MLA94807813477_102025-F.webp}', 'Novo', 'Loja oficialJBL Loja oficialFast Shop', 'https://meli.la/19JnjSN', 4.9, 0, 0, true, NULL, '2026-03-30 23:05:18.281211+00', '2026-04-01 20:27:36.881204+00', '7e8d9675-6f8b-4441-8973-0842bcb8bbd3', NULL, '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 18.7, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 5, 1000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('bccbfaf7-e6f5-4fd7-a325-7b104466d890', 'Calibrador Portátil Compressor Bomba De Ar Digital Com Lanterna LED para Encher Pneus de Carro, Moto, Bike, Bicicleta, Bola e Piscina Inflável Premium', '⚙️ Máxima Versatilidade: Ideal para pneus de carros, motos, bicicletas, bolas e muito mais! Modos predefinidos garantem ajuste rápido e preciso para cada necessidade.
