INSERT INTO public.products VALUES ('7c0f49d2-c26e-4f8e-a4ff-61756fbfb765', 'Air Fryer Digital Electrolux Experience EAF45, 5,6L, Cinza, 1400W, 127V, com Desligamento Automático e Temporizador', 'Economia de até 48% de energia para preparar refeições saborosas e mais sustentáveis.
Bolo até 17% mais uniforme, garantindo maciez por dentro e textura perfeita por fora.
Batatas até 10% mais crocantes, sem usar óleo, com resultado delicioso e dourado.
Painel digital Assistant Touch com 5 receitas sugeridas e 4 funções especiais.
Cesto de 4L com cuba total de 5,6L e dupla antiaderência para limpeza facilitada.
Tecnologia Air Cooking 360° para cozimento uniforme, crocância e maciez ideais.', 357.15, 729, 51, 'https://m.media-amazon.com/images/I/61InAn6DqaL._AC_SL1500_.jpg', '{https://m.media-amazon.com/images/I/61InAn6DqaL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61TphmgEbxL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61tj9VGgWnL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/51ICblpUCqL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61OHvZcB59L._AC_SL1500_.jpg}', NULL, 'Electrolux', 'https://amzn.to/4sGZoAA', 4.8, 0, 1, true, NULL, '2026-03-29 17:39:27.8879+00', '2026-03-29 19:27:34.706526+00', '5564c050-fcdb-4c75-a7ca-dd77d39ff4a0', '17e3558b-aeee-4d04-a007-031418f9d6ed', '31640105-56f9-43ab-8204-465c8717d731', NULL, 51.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '1cf6748a-3b9d-4d59-8946-dedaad54eea3', 'B0F24XQ9NF', 8, 300, '[{"name": "Características especiais", "value": "Desligamento automático, Programável, Resistente a manchas, Temporizador"}, {"name": "Dimensões do produto", "value": "26,7P x 34,7L x 34,6A centímetros"}, {"name": "Cor", "value": "Cinza"}, {"name": "Capacidade", "value": "5,6 Litros"}, {"name": "Material", "value": "Metal, Resina Modificada"}]', NULL, '{"prime": false, "shipping_details": "Entrega GRÁTIS: Amanhã, 30 de Março. Se pedir dentro de 7 hrs 25 mins Amanhã, 30 de Março7 hrs 25 mins"}', '{}');
INSERT INTO public.products VALUES ('83870a72-ee27-4909-a4b6-5a880f47e71e', 'Kit 4 Porta Copos de Bambu Premium Redondo c/Suporte em Metal, Descanso de Copo Resistente, Design Moderno e Elegante, Protege a Mesa Contra Riscos e Manchas, Ideal p/Copos, Xícaras e Decoração', '<ul><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ PROTEÇÃO CONTRA MANCHAS E MARCAS ] Evita anéis de copo, respingos e umidade, preservando bancadas, mesas e móveis contra danos do uso diário.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ BAMBU 100% NATURAL E DURÁVEL ] Porta copos produzidos em bambu ecológico, material resistente e renovável que mantém a estética elegante mesmo com uso frequente.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ SUPORTE ORGANIZADOR EM METAL ] Acompanha suporte de ferro resistente que mantém os porta copos organizados, facilitando o armazenamento e deixando o conjunto sempre à mão.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ DESIGN SOFISTICADO E VERSÁTIL ] Visual moderno que combina com cozinha, sala, escritório, área gourmet e ambientes decorativos, valorizando a mesa posta.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ TAMANHO IDEAL E FUNCIONAL – Ø 10 CM ] Compatível com copos, taças, canecas, xícaras e garrafas, garantindo estabilidade e proteção para diferentes tipos de bebidas.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">[ FÁCIL LIMPEZA E MANUTENÇÃO ] Superfície que facilita a limpeza — basta um pano úmido para manter o produto sempre conservado.</span></li></ul><p><br></p>', 29.89, NULL, NULL, 'https://m.media-amazon.com/images/I/61njGk5fm1L._AC_UL320_.jpg', '{https://m.media-amazon.com/images/I/61njGk5fm1L._AC_UL320_.jpg}', NULL, 'Amazon Brasil', 'https://amzn.to/4s3oMzs', 0, 0, 1, true, NULL, '2026-03-28 20:25:49.889828+00', '2026-03-29 18:18:56.091968+00', NULL, NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, NULL, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', 'B0GSCVQLCV', 8, NULL, NULL, NULL, '{"prime": false, "shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('7fe82a99-e6df-4723-87f0-7975df4108b3', 'Kit Lumina para Restauração e Liso Prolongado (4 produtos)', NULL, 161.16, 268.6, NULL, 'https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw72233cfb/Produtos/NATBRA-221670_1.jpg?sw=300&q=80', '{https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw72233cfb/Produtos/NATBRA-221670_1.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw72233cfb/Produtos/NATBRA-221670_2.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw72233cfb/Produtos/NATBRA-221670_3.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw72233cfb/Produtos/NATBRA-221670_4.jpg?sw=300&q=80}', '40% OFF', 'Natura', 'https://minhaloja.natura.com/p/kit-lumina-para-restauracao-e-liso-prolongado-4-produtos-/NATBRA-221670?position=2&listTitle=search+results+list+showcase+-+kit+shampoo&consultoria=ofertashop&marca=natura', 4.6, 0, 1, true, NULL, '2026-03-31 00:24:40.349804+00', '2026-03-31 11:08:09.108955+00', NULL, NULL, 'f729f5cd-3b0a-4ded-88d8-a5b578f0fb0b', NULL, 40.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', NULL, 'NATBRA-221670', NULL, 0, NULL, NULL, '{"shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('4ae9cc90-ceb9-490c-ad63-4660de32cd93', 'Monitor Gamer Samsung 24" FHD,120 Hz, HDMI, Preto, S3', 'Taxa de atualização de 120 Hz

Mantenha-se em ação enquanto joga, assiste a vídeos ou trabalha em projetos criativos. A taxa de atualização de 120 Hz reduz o atraso e o desfoque de movimento para que você não perca nada em momentos de ritmo acelerado.

Game Picture Mode

Configurações de jogo otimizadas, vantagem instantânea. O Game Picture Mode ajusta qualquer jogo para preencher sua tela com todos os detalhes à vista. Seus jogos com cores vivas e maior contraste de imagem para detectar inimigos escondidos no escuro.

Painel IPS

Experimente cores impressionantes em toda a tela com o painel IPS. As cores permanecem brilhantes e nítidas na tela, mesmo quando você muda de ângulo. Tons e tonalidades são representados de forma consistente e bela, com menos lavagem de cor.

Eye Saver Mode &amp; menos tremulação da tela

Proteja a sua visão e fique confortável, mesmo durante sessões longas. Mantenha o foco no seu trabalho com luz azul e tremulação da tela reduzidas.

Conectividade Múltipla

Conecte dispositivos diretamente ao seu monitor para obter maior flexibilidade, tornando seu ambiente de trabalho ainda mais conveniente.

Design Superfino

Apresentando um design superfino com bordas ultrafinas, este monitor aprimora qualquer configuração com uma aparência elegante e moderna. Desfrute de uma adição leve e elegante a qualquer ambiente.', 538.2, 899, 40, 'https://http2.mlstatic.com/D_NQ_NP_2X_652104-MLA96195278152_102025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_652104-MLA96195278152_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_619485-MLA96195435576_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_781678-MLA86414043657_062025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_905537-MLA86414083503_062025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_793113-MLA87463638659_072025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_902505-MLA96195435582_102025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_713955-MLA87137139270_072025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_882557-MLA87463502077_072025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_624336-MLA87137235808_072025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_974716-MLA87463686677_072025-F.webp}', 'Novo', 'Loja oficialEshop', 'https://meli.la/2sSTi4u', 4.9, 0, 3, true, NULL, '2026-03-30 23:12:04.578706+00', '2026-04-02 21:38:16.600301+00', '73fc119a-b8cb-4e2a-b3e2-c42abc9ce67c', '8ff943c5-492a-4b7f-9030-e6ff9d848a40', '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 40.1, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', 'b8cf1b6a-58d6-48ee-a350-0d02cc6df1f8', NULL, 5, 5000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('778fc2a2-3ae0-4b83-9601-15abf43f3a5d', 'Fatiador Profissional Multifuncional De Aço Inoxidável 16 Em 1 Para Vegetais/Frutas/Legumes', '<p>Fatiador de Cozinha Profissional 16 em 1 - Praticidade, Versatilidade e Eficiência em um só utensílio!</p><p><br></p><p>Transforme sua rotina na cozinha com o Fatiador e Ralador</p><p>Profissional 16 em 1, o aliado ideal para preparar vegetais, frutas, temperos e muito mais com agilidade e precisão.</p><p>Fabricado com lâminas em aço inoxidável de alta qualidade, este utensílio oferece cortes uniformes, rapidez no preparo e total segurança no manuseio.</p><p><br></p><p>Principais Benefícios:</p><p><br></p><p>Multifuncional: Fatie, rale, pique e corte</p><p><br></p><p>Alta Durabilidade: Lâminas afiadas em aço inox resistente à corrosão e ao uso diário.</p><p><br></p><p>Design Inteligente: Sistema de encaixe modular para facilitar a troca de lâminas e a limpeza.</p><p><br></p><p>Segurança e Praticidade: Base antiderrapante e protetor de mãos para evitar acidentes.</p><p><br></p><p>Economia de Tempo: Ideal para saladas, sopas, refogados, snacks saudáveis e muito mais.</p>', 35.88, 43.88, NULL, 'https://cf.shopee.com.br/file/br-11134207-81z1k-mhjfa9ir0mbq21', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.6472938084479116.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3617147725419827.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.2836042278039428.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.700141507781928.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.19589934195431802.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.236408321941874.webp}', NULL, 'VIVALAR SHOP', 'https://s.shopee.com.br/7AZEt64H8X', 4.8, 0, 2, true, NULL, '2026-03-30 23:21:07.200271+00', '20