INSERT INTO public.products VALUES ('7d48ed23-ccbe-42b3-bab3-0055fbc97a4d', 'Notebook ASUS VivoBook Go 15, AMD RYZEN 5 7520U, 8GB, 512GB SSD, KeepOS, Tela 15,6" FHD, Mixed Black - E1504FA-NJ732', '<p><span style="background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);">É leve. É compacto. É o ASUS Vivobook Go 15. Projetado para torná-lo produtivo e mantê-lo entretido onde quer que você vá! Com processador AMD Ryzen™ 5 7520U de excelente desempenho, 8 GB de memória RAM LPDDR51 e até 512 GB de SSD2 , ele é perfeito para seu dia a dia. Ainda conta com uma dobradiça plana de 180°, tampa física protetora na webcam e muitos recursos de design bem pensados — incluindo uma tela de 15 polegadas antirreflexo Full HD — tudo para que você vá além! O ASUS Vivobook Go 15 é equipado com um processador AMD Ryzen™ 5, 8 GB de uma rápida memória LPDDR5 e até 512 GB de armazenamento SSD, capazes de ajudá-lo a concluir todas as tarefas do dia a dia. Um acelerador AMD Radeon™ 610M ainda ajuda a potencializar a performance gráfica do notebook. O ASUS Vivobook Go 15 traz visuais incríveis graças à sua tela Full HD antirreflexiva de 15,6 polegadas. Seu design NanoEdge com bordas finas oferece mais espaço em tela para multitarefa, com proporção tela/corpo3 de 83% que garante uma ampla e imersiva exibição de imagens. O ASUS Vivobook Go 15 possui resistência4 extraordinária, atendendo ao exigente padrão de nível militar MIL-STD-810H. Isto significa que esse dispositivo passou por 12 métodos de teste rigorosos e 26 procedimentos. O resultado é um produto reconhecido pela confiabilidade e durabilidade. Esses fatores também beneficiam inerentemente a longevidade e, portanto, a sustentabilidade, para que você possa trabalhar, viajar ou relaxar com a confiança de que seu notebook ASUS está sempre preparado. O ASUS Vivobook Go 15 possui uma dobradiça plana de 180°, projetada com precisão para facilitar a visualização dos conteúdos em tela por qualquer pessoa ao redor. Sendo assim ele pode ser utilizado totalmente aberto, com um amplo ângulo visual. Além disso, vem com muitas portas de conexão capazes de mantê-lo sempre produtivo. Há uma porta USB-C® 3.2 Geração 1, uma porta USB 3.2 Geração 1 Tipo-A, uma porta USB 2.0, uma saída HDMI® e um conector de 3,5 mm para fone/microfone, essenciais para facilitar a conexão de seu ASUS Vivobook com outros periféricos, monitores e projetores. Com o ASUS Vivobook Go 15, você tem produtividade para ir além! 1. A capacidade máxima de RAM pode variar de acordo com a configuração do dispositivo. 2. A capacidade máxima do SSD pode variar de acordo com a configuração do dispositivo. 3. A proporção tela/corpo é calculada com base na área visível do corpo da tela quando o notebook é aberto a 90° e na área ativa da tela. 4. O regime de teste inclui os requisitos dos padrões de nível militar e dos testes de qualidade da ASUS e varia dependendo do dispositivo. O teste MIL-STD-810 é realizado apenas em produtos ASUS selecionados. Observe que o teste MIL-STD-810 ajuda a garantir a qualidade dos produtos ASUS, mas não indica uma adequação específica para uso militar. O teste é realizado em condições de laboratório. Qualquer dano causado por tentativas de replicar essas condições de teste será considerado acidental e não será coberto pela garantia padrão da ASUS.</span></p>', 2904.17, 4299, NULL, 'https://m.media-amazon.com/images/I/71TK+vh6JIL._AC_UL320_.jpg', '{https://m.media-amazon.com/images/I/71TK+vh6JIL._AC_UL320_.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.92557615192188.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3677267574601111.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7295899328042215.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.447305011387062.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5137215011032584.jpg