INSERT INTO public.products VALUES ('8a764795-389e-48e5-a49d-a88d203eb99e', 'Kit 2 Shorts Compressão 2 Em 1 Feminino Bermuda Para academia Caminhadas E Corrida', 'Shorts Feminino 2 em 1 – Dry Fit • P ao GG • Poliéster

