INSERT INTO public.products VALUES ('28d1f05e-c067-4725-a756-54448e085c8d', 'Kit 5 a 30 prato fundo com borda branco refeição churrasco festa jantar sopa Jogo de pratos plastico', '<p>O prato fundo é ideal para servir refeições como sopas, caldos, risotos, carnes mais encorpadas, massas entre outras refeições. </p><p><br></p><p>Informações: </p><p>- Cores: BRANCO OFF WHITE</p><p>- Formato: REDONDO</p><p>- Medidas: 2 x 23 x 2 cm (Altura x Largura x Profundidade)</p><p> - Material: Plástico</p><p>- Detalhe: Desenho de Pétala</p><p><br></p><p>Cuidados: Sempre prefira lavar em água corrente, esponja macia para não danificar a pintura e detergente de sua preferência. </p><p><br></p><p>Temos uma equipe especializada para atender todas as suas dúvidas e experiência na sua compra pela internet. Garantindo assim, a satisfação de nossos clientes.</p><p><br></p><p>ENVIO EM MENOS DE 24 HORAS - - - - PRODUTO 100% NACIONAL</p>', 13.9, 39.9, NULL, 'https://cf.shopee.com.br/file/br-11134207-7qukw-lh9n45zmoho5f7', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.12205278632137817.webp}', NULL, 'Guiba Casa&Decor', 'https://s.shopee.com.br/3LMKVvH6SC', 4.5, 0, 2, true, NULL, '2026-03-23 13:40:38.126575+00', '2026-04-02 18:38:05.286271+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 65.2, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 13, 3218, '[]', NULL, '{}', '{}');
INSERT INTO public.products VALUES ('16633278-1eda-4b14-8d7e-8f70d7877944', 'Aparador De Pelos Super Groom 10 Mondial Preto/branco Bg-08', '"O Aparador de Pelos SuperGroom White possui a funcionalidade de 10 produtos em apenas 1! Conta com 5 aparadores para cabelo, rosto e corpo, 4 pentes de corte com guias de 3, 6, 9 e 12mm, além de pente ajustável para a remoção dos pelos no comprimento que preferir. Suas lâminas em aço inox oferece alto desempenho para um corte rente, preciso e suave. Saiba mais sobre o BG-08 da Mondial:

10 EM 1 - MÚLTIPLAS FUNÇÕES
O aparador de pelos da Mondial vem com 10 acessórios: são 5 tipos de aparadores de alto desempenho e 5 pentes de corte com diferentes opções de altura para aparar e remover os pelos do rosto e do corpo inteiro. Você pode ter uma aparência impecável sem sair de casa!

PENTES DE CORTE + PENTE AJUSTÁVEL
Acompanha 4 pentes de corte com 3mm, 6mm, 9mm e 12mm, além de pente ajustável com 16 níveis de altura, para aparar os pelos no comprimento que preferir.

APARADOR DE CABELO
Ideal para aparar os pelos do rosto, pescoço e corpo com total praticidade. Garante o corte rente à pele quando usado sem pente de corte.

APARADOR DE BARBA E BIGODE + PRECISÃO
Os aparadores são perfeitos para aparar com precisão a barba e áreas menores, como pequenas linhas e detalhes.

APARADOR PARA NARIZ E ORELHA
Remove os pelos do nariz e orelhas com total conforto e praticidade.

MICROBARBEADOR
Sistema exclusivo para aparar e raspar com suavidade os pelos rente à pele.

LÂMINAS EM AÇO INOX
As lâminas em aço inox asseguram um corte rente, preciso e suave. Além disso, garantem maior durabilidade ao produto.

MAIS TEMPO DE USO
A bateria recarregável de Ion Lithium garante até 90 minutos de uso sem fio. Além disso, o produto é bivolt, perfeito para usar em qualquer lugar!

BASE ORGANIZADORA
Além de organizar os acessórios adequadamente, evitando que fiquem soltos e espalhados, também pode ser utilizada como base para carregamento.

LUZ INDICADORA
Indica o nível da bateria para carregamento.', 103.55, 109, 5, 'https://http2.mlstatic.com/D_NQ_NP_2X_951680-MLA99958222443_112025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_951680-MLA99958222443_112025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_866557-MLA82166418736_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_917835-MLA82166418782_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_932165-MLA82449455847_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_767154-MLA82166437702_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_858894-MLA82166496302_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_650003-MLA82166496316_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_987018-MLA82449455927_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_898878-MLA82166418880_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_681013-MLA82166418894_022025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_902943-MLA80302691768_112024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_683969-MLA80560318265_112024-F.webp}', 'Novo', 'BRAIMPORTACAO', 'https://meli.la/2o8e6vH', 5, 0, 1, true, NULL, '2026-04-02 18:31:51.288055+00', '2026-04-02 21:27:28.690494+00', 'fdf8a6c1-fa11-4c4a-ab57-e730739505a8', '5f3bcfe0-f6e4-47b2-bcb0-f95f88137537', '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 5.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '95a00be7-7f36-4590-a2d9-f78cd0a12689', NULL, 16, 4, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
