INSERT INTO public.products VALUES ('74efd910-bda7-4a0f-aeed-ca28f5a26589', 'Vasinho de cerâmica com folhagem de eucalipto artificial para decoração', '<p>Vasinho de cerâmica branca com plantinha folhagem artificial de eucalipto: perfeito para decorar sua casa, seu evento e presentear alguém especial.</p><p><br></p><p>Descrições do produto:</p><p>Composição: cerâmica.</p><p>Altura do vaso: 7 cm</p><p>Altura do vaso com folhagem: 13 cm</p><p>Diâmetro do vaso: 9 cm</p><p>O que vem na embalagem: 1 vaso em cerâmica com folhagem artificial eucalipto.</p><p><br></p><p>Nossos arranjos são montados com argila branca e musgo natural para melhor sustentação e um acabamento impecável.</p>', 19.99, NULL, NULL, 'https://cf.shopee.com.br/file/br-11134201-23020-1ynwkyhmmmnv67', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7608134790330794.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.576245864597668.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.4137802387956362.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.08791684215353124.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3521264965111066.webp}', NULL, 'É de-coração store', 'https://s.shopee.com.br/1VusC8ECLq', 4.8, 0, 1, true, NULL, '2026-03-31 00:11:12.060227+00', '2026-03-31 15:00:46.391988+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, NULL, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 7, 1802, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 19410887832, "shopee_shopid": 524979442}', '{}');
INSERT INTO public.products VALUES ('1e577309-011d-477c-8b92-b74a661d5bbe', 'Porto Brasil Conjunto com 6 Pratos de Sobremesa Orgânico Oceano', '<ul><li>Seguro para freezer, forno, lava-louças e microondas</li><li>Esmalte Reagente</li><li>Esmaltes cerâmicos em geral possuem uma dureza superior à maioria dos metais utilizados na fabricação de talheres. O que ocorre normalmente não é um risco e sim um desgaste do metal sobre a peça. Neste caso indicamos a aplicação de produtos com saponáceo para remoção dos resíduos.</li><li>Livre de Cadmio e Chumbo</li><li>Segurança alimentar garantida e embalagens 100% recicláveis</li></ul><p><br></p>', 124.99, 145.37, NULL, 'https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/1774975805605-werlu5h69lg.jpg', '{https://m.media-amazon.com/images/I/717NRV6w6FL._AC_UL320_.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3319147680357679.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.31787696518882613.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.004935263138348023.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3852156767323508.jpg}', 'Ofertas 4.4', 'Amazon Brasil', 'https://amzn.to/4sQRC7q', 4.6, 0, 2, true, NULL, '2026-03-31 16:47:43.325091+00', '2026-03-31 18:56:49.972401+00', '7bfafede-dff2-40d7-9ae6-2ed97d510454', 'a50a8537-ee60-43eb-99ee-6f8b15f53211', '31640105-56f9-43ab-8204-465c8717d731', NULL, 14.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', 'B0CV6SS7W1', 8, NULL, NULL, NULL, '{"prime": false, "shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('c9819c07-c8d6-421d-bf98-8913090c80b1', 'LANCAMENTO CELULAR XIAOMI POCO X8 PRO 5G NFC 256GB OU 512GB VERSÃO GLOBAL FONTE RAPIDA COM CAPINHA', '<p>📱 POCO X8 Pro 5G – 8GB RAM | Dimensity 8500 Ultra | Tela AMOLED 120Hz | Câmera 50MP | Bateria 6500mAh</p><p><br></p><p>O novo POCO X8 Pro 5G chega trazendo tecnologia de última geração, desempenho extremo e bateria gigante para quem exige velocidade, qualidade e autonomia. Equipado com o poderoso MediaTek Dimensity 8500 Ultra, tela AMOLED ultra brilhante e carregamento super rápido de 100W, ele é perfeito para jogos, trabalho e entretenimento.</p><p><br></p><p>⚡ Desempenho poderoso</p><p>Com o processador Dimensity 8500 Ultra (4nm) e GPU Mali-G720 MC8, o POCO X8 Pro oferece alto desempenho para rodar jogos pesados, multitarefa e aplicativos exigentes com extrema fluidez.</p><p><br></p><p>-ARMAZENAMENTO INTERNO:</p><p>256GB</p><p>512GB </p><p>-RAM:</p><p>8GB </p><p>Memória de alta velocidade UFS 4.1 para carregamentos muito mais rápidos.</p><p><br></p><p>🖥️ Tela AMOLED 120Hz ultra brilhante</p><p>A tela de 6.59" AMOLED entrega imagens impressionantes com cores vibrantes e fluidez incrível.</p><p>✔ 120Hz taxa de atualização</p><p>✔ Dolby Vision + HDR10+</p><p>✔ HDR Vivid</p><p>✔ Brilho máximo de 3500 nits</p><p>✔ Resolução 1268 × 2756 (1.5K)</p><p>✔ 3840Hz PWM Dimming (mais conforto para os olhos)</p><p>Perfeita para jogos, filmes e redes sociais.</p><p><br></p><p>📸 Câmera dupla com 50MP</p><p>Capture fotos nítidas e vídeos de alta qualidade com o sistema de câmera avançado.</p><p>Câmera principal</p><p>50MP com OIS (estabilização óptica)</p><p>HDR e modo panorama</p><p>Câmera ultrawide</p><p>8MP</p><p><br></p><p>🎥 Vídeo:</p><p>4K até 60fps</p><p>Slow motion até 960fps</p><p>HDR10+</p><p><br></p><p>📷 Câmera frontal:</p><p>20MP para selfies e chamadas de vídeo em alta definição.</p><p><br></p><p>🔋 Bateria gigante + carregamento ultrarrápido</p><p>Com 6500mAh, o POCO X8 Pro oferece bateria para o dia inteiro ou mais.</p><p>⚡ Carregamento rápido de 100W</p><p><br></p><p>🔊 Som estéreo premium</p><p>Alto-falantes estéreo</p><p>Áudio Hi-Res 24bit / 192kHz</p><p>Hi-Res Wireless</p><p><br></p><p>📡 Conectividade completa</p><p>✔ 5G ultra rápido</p><p>✔ Wi-Fi 6</p><p>✔ Bluetooth 5.4</p><p>✔ NFC</p><p>✔ GPS multibanda</p><p>✔ Sensor digital na tela</p><p>✔ Infravermelho (IR Blaster)</p><p><br></p><p>💧 Resistência</p><p>Certificação IP68 / IP69K</p><p>✔ Resistência à água</p><p>✔ Resistência à poeira</p><p><br></p><p>📦 Especificações principais</p><p>Sistema: Android 16 + HyperOS 3</p><p>Tela: 6.59" AMOLED 120Hz</p><p>Processador: Dimensity 8500 Ultra</p><p>RAM: 8GB </p><p>Armazenamento: 256GB OU 512GB</p><p>Câmera: 50MP + 8MP</p><p>Selfie: 20MP</p><p>Bateria: 6500mAh</p><p>Carregamento: 100W</p><p>Rede: 5G</p><p>Dual SIM</p>', 2483.08, 2699, 13, 'https://cf.shopee.com.br/file/sg-11134201-8261k-mlnuyfo72ia7cb', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7211513620201746.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7961129246100126.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.11215794765784082.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.8198322677482891.webp}', NULL, 'CBO COMERCIAL', 'https://s.shopee.com.br/AACtCqJami', 4.8, 0, 2, true, NULL, '2026-04-01 16:40:57.641921+00', '2026-04-02 18:38:19.558779+00', '562df9b8-8a3a-419d-bce3-152b980c7927', 'a5c36a6e-033f-43a4-a4f3-2ace904ef8c7', '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 8.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '3ef27b40-a2db-4664-abe6-7a1cccd8e9a3', NULL, 5, 62, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 58206670114, "shopee_shopid": 1351433975}', '{}');
INSERT INTO public.products VALUES ('157fa30f-84ac-4617-b78b-0d26771191d7', 'Balança Bioimpedância Digital Profissional Suporta Até 140kg via Bluethooth', '<p>Balança Digital com Bioimpedância – Tecnologia, Estilo e Saúde em um só produto!</p><p>Melhore sua performance diariamente com dados precisos sobre o seu corpo.</p><p>Com conexão via Bluetooth ao app OKOK-International (IOS e Android), você acompanha sua evolução de forma inteligente e visual.</p><p><br></p><p>Monitore indicadores essenciais:</p><p>•	Peso</p><p>•	IMC</p><p>•	Nível de Água</p><p>•	Gordura Visceral</p><p>•	Massa Óssea</p><p>•	Nível de Proteína</p><p>•	Obesidade</p><p>•	Idade Corporal</p><p>•	LBM (massa magra)</p><p><br></p><p>Características da balança:</p><p>•	Capacidade de até 140kg</p><p>•	Registra até 4 perfis de usuário</p><p>•	Conexão Bluetooth com o app</p><p>•	Mede IMC e gordura corporal</p><p>•	Display digital em LED iluminado</p><p>•	Plataforma de vidro antiderrapante</p><p>•	Funciona com 2 pilhas AAA (não inclusas)</p><p>•	Desligamento automático</p><p>•	Acionamento automático ao subir na balança</p><p>•	Design ultrafino, compacto e elegante</p><p>•	Vidro temperado e acabamento sofisticado</p><p>•	Unidades: Kg / Lb</p><p>•	Indicação de carga de bateria</p><p><br></p><p>Dimensões: </p><p>•	26cm de largura</p><p>•	26cm de comprimento</p><p>•	3cm de altura</p><p> </p><p>OBS:  </p><p> Não use em carpete ou superfície macia </p><p> Pise cuidadosamente </p><p>Configure o APP de acordo com o manual de instrução para um funcionamento perfeito</p><p><br></p><p><br></p><p>Balança Digital Simples – Precisa, Elegante e Eficiente!</p><p><br></p><p>Chegou a balança que une tecnologia, estilo e praticidade para você acompanhar sua saúde com precisão todos os dias!</p><p><br></p><p>Destaques do produto:</p><p>•	Alta precisão – sensores inteligentes com variação de 100g</p><p>•	Suporta até 180kg</p><p>•	Vidro temperado premium – resistente e moderno</p><p>•	Display digital com leitura automática</p><p>•	Desligamento automático – economia de energia</p><p>•	Design elegante – combina com qualquer ambiente</p><p>•	Tamanho compacto: 29x29cm</p><p>•	Funciona com pilhas ou bateria (não inclusas)</p><p><br></p><p>Ideal para:</p><p>•	Quem busca controle de peso com praticidade</p><p>•	Pessoas ativas que acompanham resultados</p><p>•	Quem valoriza qualidade, durabilidade e bom gosto</p><p><br></p><p>Fácil de usar, fácil de confiar.</p><p>Invista em sua saúde com quem entrega precisão de verdade.</p><p><br></p><p>Dimensões: </p><p>•	29cm largura </p><p>•	29cm comprimento</p><p>•	3cm altura</p><p><br></p><p>Itens Incluso:</p><p>1 Unidade: Balança de Vidro Temperado </p><p>1 Manual de Instruções Português</p><p><br></p><p>OBS:  </p><p> Não use em carpete ou superfície macia </p><p> Pise cuidadosamente</p>', 32.97, 34.97, NULL, 'https://cf.shopee.com.br/file/br-11134207-7r98o-m314shpkk6px3e', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.597393763977554.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.25749541302023793.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5030073708777684.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.39317450942447296.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.012686863724597486.webp}', NULL, 'Universo Mix Utilidades', 'https://s.shopee.com.br/6L0Aez8h18', 4.9, 0, 1, true, NULL, '2026-04-01 16:56:53.478661+00', '2026-04-02 02:29:49.445883+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', 'br-11110105-6v5do-mfjsvfeqz4lh0f.16000081759845615.mp4', 5.7, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 12, 4810, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 20697751196, "shopee_shopid": 511410160}', '{}');
INSERT INTO public.products VALUES ('1cfc3fb3-b188-493c-899f-8136ce44e003', 'Echo Spot com Alexa (Geração mais recente) | Despertador inteligente com som vibrante | Cor Preta', 'CONHEÇA O ECHO SPOT - Um despertador inteligente com som vibrante e Alexa. Sempre pronto para te ajudar a acordar, relaxar e muito mais.
DESPERTADOR INTELIGENTE PERSONALIZÁVEL - Veja facilmente a hora, a previsão do tempo e nomes de música, controle dispositivos de casa inteligente e muito mais. Personalize o display com seu design preferido de relógio e cores divertidas.
SOM POTENTE E VIBRANTE - Curta sons com vocais nítidos e graves profundos. É só pedir para Alexa reproduzir música, podcasts e audiolivros. Veja o título do que está tocando e controle sua música também por toque.
SUA VIDA MAIS FÁCIL - Crie uma rotina de Alexa para acordar aos poucos ao som de música e com iluminação gradual. Veja rapidamente a hora, confira os lembretes ou peça para Alexa dizer a previsão do tempo.
SUA CASA MAIS CONFORTÁVEL - Controle dispositivos de casa inteligente compatíveis. É só pedir para Alexa ou tocar no display para ligar ou desligar luzes inteligentes. Crie rotinas para desligar o ar-condicionado quando você sair de casa ou acender as luzes ao pôr do sol.
DESENVOLVIDO PARA PROTEGER A SUA PRIVACIDADE - A Amazon não vende informações pessoais de clientes. O Echo Spot foi construído com várias camadas de controles de privacidade, incluindo o botão de desligar o microfone e controles no aplicativo.
DESENVOLVIDO PENSANDO NA SUSTENTABILIDADE - Esse dispositivo foi feito com 36% de materiais reciclados.', 479, 579, NULL, 'https://m.media-amazon.com/images/I/718KFI+hBOL._AC_SL1500_.jpg', '{https://m.media-amazon.com/images/I/718KFI+hBOL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71Qtzczw2fL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71U8FUH7FDL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71CrkAgNKNL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71JD11eJ+5L._AC_SL1500_.jpg}', 'Ofertas 4.4', 'Amazon', 'https://amzn.to/4m3Wl2E', 4.8, 0, 2, true, NULL, '2026-04-01 14:58:28.501573+00', '2026-04-01 20:57:00.150122+00', 'ef395dcf-cccc-4966-938e-0aa7d16f6d0f', NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 17.3, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', 'b8cf1b6a-58d6-48ee-a350-0d02cc6df1f8', 'B0C2RS4ZG6', 9.5, 2000, NULL, NULL, '{"prime": false, "social_copy": {"model": "stepfun/step-3.5-flash:free", "content": {"reels_hook": "Oferta relâmpago: Echo Spot 17% OFF! ⚡", "whatsapp_message": "🔥 Oferta imperdível! Echo Spot com Alexa por R$ 479,00 (17% OFF). Despertador inteligente com som vibrante, controle de smart home e muito mais. Avaliação 4.8/5 - mais vendido! 🚨 Estoque limitado. Compre já: https://amzn.to/4m3Wl2E", "instagram_captions": ["Acorde com tecnologia e estilo! 🛏️⏰ O Echo Spot está com 17% OFF por tempo limitado! São R$ 100 de economia para você ter um despertador inteligente com Alexa. Avaliação 4.8/5 - mais vendido! 🚨 Últimas unidades! Não perca essa chance. Compre aqui 👇 https://amzn.to/4m3Wl2E #oferta #desconto #smarthome #alexa #tecnologia #echospot #despertadorinteligente #amazon", "Transforme sua rotina com o Echo Spot! ☀️ Despertador personalizável, som vibrante e controle de dispositivos via Alexa. Com 4.8/5 estrelas, é o favorito dos usuários! 💥 Desconto de 17% - só até acabar o estoque! Aproveite agora! 👉 https://amzn.to/4m3Wl2E #oferta #desconto #smartdevices #alexabrasil #technology #echospot #despertador #amazon