INSERT INTO public.products VALUES ('5353db0e-e430-4c53-879e-3c187d777f13', 'Oster Cafeteira Flavor Programável, Vermelha, 220v,', 'Painel digital programável em aço inox, permite programar a hora ideal para você ter o seu café fresquinho e conta com o seletor de intensidade de pó, que possibilita escolher a dosagem certa para um café mais forte ou mais fraco.
Capacidade para fazer 36 xícaras de 42ml, escolhendo a intensidade para um café mais forte ou mais fraco
Função Timer que indica quanto tempo passou desde o preparo do seu café.
Filtro em Nylon, removível e lavável, transformando a limpeza da sua cafeteira muito mais eficiente.
Aviso sonoro, a Cafeteira Digital Oster emite um sinal sonoro para avisar quando seu café está pronto.', 196.11, 299, NULL, 'https://m.media-amazon.com/images/I/51HQ6ID+8sL._AC_SL1000_.jpg', '{https://m.media-amazon.com/images/I/51HQ6ID+8sL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/51pmhzAqsbL._AC_SL1000_.jpg,https://m.media-amazon.com/images/I/41gyNqxLZ8S._AC_SL1000_.jpg}', 'Menor preço em 365 dias', 'Oster', 'https://amzn.to/4c90WgJ', 5, 0, 0, true, NULL, '2026-03-26 23:00:10.702295+00', '2026-04-02 18:36:24.323145+00', '77f33f36-2389-4d43-856e-cead4472697c', NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 34.4, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '1cf6748a-3b9d-4d59-8946-dedaad54eea3', 'B076F9GTBC', 8, 200, '[{"name": "Marca", "value": "Oster"}, {"name": "Capacidade", "value": "1,5 Litros"}, {"name": "Cor", "value": "Vermelha"}, {"name": "Características especiais", "value": "Programável"}, {"name": "Tipo de cafeteira", "value": "Máquina de café gota a gota"}]', NULL, '{"prime": false, "price_analysis": {"verdict": "Preço atual é o melhor encontrado e oferece desconto moderado.", "savings_tip": "Aproveite datas como Prime Day ou Black Friday para buscar descontos mais significativos.", "is_good_deal": true, "published_at": "2026-03-27T07:30:38.924Z", "best_platform": "Amazon", "recommendation": "Não há outras plataformas com preço menor para este modelo; se você precisa da cafeteira agora, comprar na Amazon é a opção mais vantajosa. Caso possa esperar, aguarde promoções sazonais para garantir um desconto maior."}, "shipping_details": "Entrega GRÁTIS: quarta-feira, 1 de Abril. Se pedir dentro de 14 hrs 59 mins. Ver detalhes quarta-feira, 1 de Abril14 hrs 59 mins"}', '{}');
INSERT INTO public.products VALUES ('ffcca84e-480e-4caf-ac5b-45adf54d5e16', 'Ovo De Páscoa Lindt Swiss Classic Ao Leite 130g', '<p><span style="background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.8);">O Ovo de Páscoa Swiss Classic 130g é uma verdadeira obra-prima da tradição suíça, ideal para os amantes de chocolate ao leite. Com uma casca de chocolate ao leite premium, rica e cremosa, este ovo proporciona uma experiência única e sofisticada. Seu sabor marcante e delicado reflete o cuidado e a expertise de mais de 175 anos da Lindt na arte do chocolate. Este produto, que vem em uma elegante embalagem de papel, é perfeito para presentear ou para saborear em momentos especiais. Além disso, é importante ressaltar que o ovo não contém glúten, tornando-se uma opção acessível para muitos. Com um peso líquido de 130 g, é uma escolha ideal para quem busca qualidade e sabor em um único produto. Desfrute da tradição e do sabor incomparável da Lindt com o Ovo de Páscoa Swiss Classic.</span></p>', 94.99, 99.99, 5, 'https://cf.shopee.com.br/file/br-11134207-81zuh-mkviscpzcz5td1', '{}', NULL, 'Lindt', 'https://s.shopee.com.br/9fGWW3z7Sv', 4.6, 0, 2, true, NULL, '2026-03-28 20:57:12.263959+00', '2026-04-02 18:38:12.417899+00', '0fb8f3f1-9e06-47bf-ae8f-915e9d21a018', NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 5.0, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', '4aefe9fb-8c07-4342-9160-f0a65922c4ad', NULL, 16, 330, '[]', NULL, '{}', '{}');
INSERT INTO public.products VALUES ('8561c5f3-0dae-4e2b-a861-46c736404b48', 'Smart TV 32 polegadas LED HD Wi-Fi TV 60Hz 32wdsnbx 100/240v Android 14', NULL, 809.59, 879.99, NULL, 'https://cf.shopee.com.br/file/cn-11134207-7ras8-mcpxy3beiwrt0d', NULL, NULL, 'TOP DJM', 'https://s.shopee.com.br/1gELbyjTvy', 4.8, 0, 2, true, NULL, '2026-04-02 00:36:35.964941+00', '2026-04-02 10:56:49.184784+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 8.0, '18826abb-41b4-49d6-a62d-1ec9b3a0ddb6', NULL, NULL, 5, 997, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 43308653347, "shopee_shopid": 1470360466}', '{}');
INSERT INTO public.products VALUES ('ee9c71c4-2376-4564-a7ed-fa8dab4e2891', 'Carrinho Organizador Multiuso 3 Prateleiras com Rodinhas para Cozinha Banheiro Salão Manicure Cabeleireiro (Preto)', '<ul><li>Design Compacto - Com três prateleiras espaçosas, o carrinho oferece amplo armazenamento sem ocupar muito espaço, perfeito para ambientes menores.</li><li>Facilidade de Movimentação - Equipado com rodas resistentes, permite fácil transporte entre diferentes cômodos, proporcionando praticidade no dia a dia.</li><li>Versatilidade de Uso - Ideal para diversos ambientes como banheiros, salões de beleza, cozinhas e até escritórios. Organize seus itens com praticidade em qualquer espaço.</li><li>Durabilidade e Resistência - Fabricado com materiais de alta qualidade, garante resistência e longa vida útil, suportando o uso diário sem perder a funcionalidade.</li><li>Funcionalidade - Organize de maneira eficiente itens diversos como produtos de higiene, cosméticos, utensílios de cozinha e muito mais, mantendo tudo ao alcance das mãos.</li></ul><p><br></p>', 55.9, 72, NULL, 'https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/1775055163844-4r7c093yjl8.jpg', '{https://m.media-amazon.com/images/I/51HgGLlihlL._AC_UL320_.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.013107916899505079.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7242626341983167.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.28247315890251956.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3464129892387129.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7490564208114339.jpg}', 'Ofertas 4.4', 'Amazon Brasil', 'https://amzn.to/4vjZv6W', 4.3, 0, 1, true, NULL, '2026-04-01 14:49:50.569971+00', '2026-04-01 15:58:49.544111+00', NULL, NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 22.4, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', 'B0DSCC344G', 8, NULL, NULL, NULL, '{"prime": false, "shipping_details": "Consultar frete"}', '{}');
INSERT INTO public.products VALUES ('568306da-c52c-42c1-acfb-960261d39032', 'Kit Tododia Algodão com Hidratante, Body Splash e Sabonete em Barra (3 produtos)', '<p>Todo dia é dia de se cuidar com Tododia Algodão.</p><p>• fórmulas com ingredientes naturais e nutrição prebiótica que se adapta ao que sua pele precisa</p><p>• sabonete em barra que limpa suavemente, sem agredir a pele, deixando uma sensação de frescor e maciez a cada uso, além de preparar a pele para absorver o creme corporal</p><p>• creme corporal que nutre até as camadas mais profundas com uma textura cremosa e perfumada</p><p><br></p><p>• body splash com fragrância floral suave, notas cítricas, frutais e um toque delicado de doçura• sensação gostosa de banho tomado em qualquer momento do dia.</p><p>&nbsp;</p><p><strong>contém:</strong></p><p>1 caixa de sabonetes em barra Tododia Algodão (5 sabonetes com 90 g cada)</p><p>1 creme para o corpo Tododia Algodão 400 ml</p><p>1 body splash Tododia Algodão 200 ml</p>', 124.62, 207.7, NULL, 'https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw140eea91/Produtos/NATBRA-215255_1.jpg?sw=300&q=80', '{https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw140eea91/Produtos/NATBRA-215255_1.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dw140eea91/Produtos/NATBRA-215255_2.jpg?sw=300&q=80}', '40% OFF', 'Natura', 'https://minhaloja.natura.com/p/kit-tododia-algodao-com-hidratante-body-splash-e-sabonete-em-barra-3-produtos/NATBRA-215255?position=9&listTitle=search+results+list+showcase+-+sabonete&consultoria=ofertashop&marca=natura', 4.8, 0, 3, true, NULL, '2026-03-27 21:52:55.864394+00', '2026-04-01 17:39:49.949215+00', 'abbed348-d0b2-42d9-a2a9-ff8c1ec9f689', '5cbe6e44-319e-40d3-8f78-e32d09234a7a', 'f729f5cd-3b0a-4ded-88d8-a5b578f0fb0b', NULL,