INSERT INTO public.products VALUES ('c934d8fd-e540-49d7-a51b-bc44e88e822c', 'Kit 25/50 Cabides Veludo Adulto Para Roupas Ultrafino Resistente Antideslizante Rotação 360° Slim Preto', '<p>Kit 25/50 Cabides Veludo Adulto Para Roupas Ultrafino Resistente Antideslizante Rotação 360° Slim Preto</p><p><br></p><p>O Kit de Cabides de Veludo é perfeito para organizar suas roupas com praticidade e elegância. Feitos com um revestimento de veludo antiderrapante, os cabides evitam que as peças escorreguem, mantendo-as sempre no lugar. Seu design fino economiza espaço no guarda-roupa, enquanto o gancho giratório facilita o uso. Ideais para roupas delicadas, como vestidos, ternos, camisas e blusas de alça, os cabides são leves, resistentes e ajudam a preservar a forma das peças. Um acessório indispensável para quem busca organização e cuidado com suas roupas.</p>', 34.9, 66.9, 82, 'https://cf.shopee.com.br/file/br-11134207-7r98o-m3xjx4tqzy2g5a', '{}', NULL, 'L.A UTILIDADES', 'https://s.shopee.com.br/20rC1GVN5C', 4.9, 0, 1, true, NULL, '2026-04-02 00:46:23.66382+00', '2026-04-02 18:38:22.300243+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 47.8, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '863befde-b087-4dee-bc39-36e519b18a48', NULL, 7, 1514, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 19897996786, "shopee_shopid": 351549429}', '{}');
INSERT INTO public.products VALUES ('ad384c13-b0f4-4338-98ab-2c07f785b4fe', 'WAP Ventilador de Mesa e Parede 50cm FLOW TURBO, Tecnologia Silenciosa e Econômica, 8 Pás e 3 Velocidades, 180W 127V', '<ul><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">Com potência de 180W e 8 pás, é ideal para quem busca ventilação eficiente em ambientes amplos, garantindo maior vazão de ar em longa distância.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">Possui tecnologia de Silent Flow, proporcionando menos ruído na velocidade 1, e nas velocidades 2 e 3 tem maior performance do vento.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">Conta com o selo PROCEL e o Triplo A que garante máxima eficiência energética, proporcionando ventilação potente e mais economia no dia a dia.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">Como modelo 2 em 1, adapta-se facilmente a qualquer ambiente, permitindo o uso sobre a mesa ou fixado na parede com a mesma base.</span></li><li><span style="color: var(--__dChNmAmGoMXsw4B,#0f1111);">Com design leve e moderno, o ventilador oferece praticidade e conforto. Para maior durabilidade, manuseie com cuidado e consulte e siga o manual de instruções.</span></li></ul><p><br></p>', 164, 311.09, NULL, 'https://m.media-amazon.com/images/I/8194vs7pwxL._AC_UL320_.jpg', '{https://m.media-amazon.com/images/I/8194vs7pwxL._AC_UL320_.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.5352177027751952.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.17837785818144836.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7564549916595971.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.8178391742126034.jpg,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.3174610444107804.jpg}', 'Ofertas 4.4', 'Amazon Brasil', 'https://amz