INSERT INTO public.products VALUES ('82adb4d1-a3b0-4850-87e3-59a863402f60', 'Kit Shampoo, Condicionador e Máscara Lumina Antiqueda e Crescimento', '<p>Trio que combate a queda e estimula o crescimento saudável dos fios.</p><p><strong>•</strong>&nbsp;shampoo que limpa, estimula o couro cabeludo e&nbsp;<strong>reduz em 2 vezes a queda por quebra</strong></p><p><strong>•</strong>&nbsp;condicionador que hidrata e&nbsp;<strong>promove 6 vezes mais resistência</strong></p><p><strong>•</strong>&nbsp;cabelos 8 vezes mais fáceis de pentear</p><p><strong>•</strong>&nbsp;máscara com&nbsp;<strong>ação antiquebra profunda</strong>&nbsp;que deixa os cabelos até 9 vezes mais fortes</p><p><strong>•</strong>&nbsp;3 vezes mais maciez sem pesar</p><p><strong>• bioproteína tripla ação e ativo dermoativador</strong>: atuam no preenchimento inteligente dos danos internos e na reparação externa da fibra capilar</p><p><strong>•</strong>&nbsp;cabelos mais resistentes, encorpados e com vitalidade.</p><p>&nbsp;</p><p><strong>contém</strong></p><p>1 shampoo estimulante 300 ml</p><p>1 condicionador fortificante 300 ml</p><p>1 máscara antiquebra 50 ml.</p>', 90.42, 150.7, NULL, 'https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwf8da75b9/Produtos/NATBRA-228239_1.jpg?sw=300&q=80', '{https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwf8da75b9/Produtos/NATBRA-228239_1.jpg?sw=300&q=80}', '40% OFF', 'Natura', 'https://minhaloja.natura.com/p/kit-shampoo-condicionador-e-mascara-lumina-antiqueda-e-crescimento/NATBRA-228239?position=6&listTitle=search+results+list+showcase+-+shampoo+antiqueda&consultoria=ofertashop&marca=natura', 5, 0, 0, true, NULL, '2026-04-02 00:18:48.600848+00', '2026-04-02 20:37:50.103429+00', 'abbed348-d0b2-42d9-a2a9-ff8c1ec9f689', NULL, 'f729f5cd-3b0a-4ded-88d8-a5b578f0fb0b', NULL, 40.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '95a00be7-7f36-4590-a2d9-f78cd0a12689', 'NATBRA-228239', NULL, 0, NULL, NULL, '{"shipping_details": "Consultar frete"}', '{"latest": {"feed": {"legendas": ["O KIT que VIRALIZOU e promete ACABAR com a queda! Shampoo, condicionador e mascara por 40% OFF. Resultados em 2x menos quebra e 6x mais resistencia. Seu cabelo 8x mais facil de pentear. Comente QUERO para saber como comprar!\n\n#CabeloPerfeito #Antiqueda #CrescimentoCapilar #Natura #OfertaRelampago #Beleza #Cabelos #Tendencia #Desconto #PresenteDiaDasMaes", "Cansada de ver cabelo no chuveiro? Esse trio da Natura e a solucao! Limpeza que estimula o couro cabeludo e reduz a queda. Hidratacao profunda com mascara antiquebra. Cabelos fortes e com brilho extremes. Corre que o estoque voa! Link na bio 👆\n\n#CuidadosCapilares #ShampooAntiqueda #CondicionadorHidratante #MascaraCapilar #CabeloSaudavel #DicaDeBeleza #Promocao", "Presente perfeito para o Dia das Maes que merece cabelos impecaveis! Kit completo Natura Lumina com 40% de desconto. Acaba com a queda, fortalece e deixa os fios lisos. Garanta ja e surpreenda! \n\n#PresenteDiaDasMaes #KitCabelo #NaturaLumina #Beleza feminina #OfertaEspecial #CabeloGrowth #ImpulsionaCabelo"]}, "reels": {"cenas": [{"cena": 1, "audio": "Som de impacto e transicao rapida. Narração curta e energetica: ''Isso Viralizou!''", "duracao": "0-2s", "acao_visual": "Close rapido em frasco de shampoo Natura Lumina brilhando em superficie espelhada com luz de studio. Elementos graficos de \"40% OFF\" surgem com efeito sonoro de caixa registradora.", "texto_sobreposto": "O KIT QUE ACABOU COM MINHA QUEDA\n40% OFF"}, {"cena": 2, "audio": "Som de agua e narração: ''Condicionador que repara.''", "duracao": "2-4s", "acao_visual": "Transicao para frasco de condicionador sendo derramado em cabelo humedo e brilhante (close no fio). Texto animado: ''6X Mais Resistencia''.", "texto_sobreposto": "HIDRATACAO QUE FORTALECE\n6X MAIS RESISTENCIA"}, {"cena": 3, "audio": "Som de pente passando macio e narração: ''Mascara com acao antiquebra profunda.''", "duracao": "4-6s", "acao_visual": "Cena da mascara cremosa sendo aplicada em cabelos, com efeito de fios ficando lisos e alinhados instantaneamente. Texto: ''8X Mais Facil de Pentear''.", "texto_sobreposto": "DESEMARANHAMENTO PERFEITO\n8X MAIS FACIL"}, {"cena": 4, "audio": "Musica atinge pico. Narração final urgente: ''Compre agora antes que acabe. Corre!''", "duracao": "6-8s", "acao_visual": "Montagem rapida dos tres produtos alinhados em primeiro plano com fundo rosa pastel e luz suave. Texto grande e centralizado: ''Queda Reduzida em 2X''. Incluir selo de ''5/5 Avaliacoes''.", "texto_sobreposto": "TRIO COMPLETO\nREDUZ A QUEDA EM 2X\n5/5 ESTRELAS"}], "audio_sugerido": "Som de batida rapida e moderna, trend do TikTok (ex: ''Espresso'' instrumental ou som de ''POSSESSIVE'' remix)"}, "stories": {"enquete": {"opcao1": "EU, claro!", "opcao2": "MINHA MAE", "pergunta": "Voce ou sua mae mais precisa desse kit?"}, "texto_curto": "Presente dos sonhos para a mae que ama cabelos bonitos! 💖"}, "whatsapp": {"mensagem": "OLHA O PRESENTE PERFEITO PRO DIA DAS MAES! 🤯\n\nAcabou de chegar o KIT NATURA LUMINA com 40% OFF! 💇‍♀️✨\n\nECombate queda + estimula crescimento saudavel dos fios.\n\n✅ Shampoo reduz a queda por quebra em 2X\n✅ Condicionador promove 6X mais resistencia\n✅ Mascara antiquebra profunda\n✅ Cabelos 8X mais faceis de pentear\n\nDe R$ 150,70 por  R$ 90,42 🎉\n\nCorre que o estoque voa! Esse e o presente que expressive amor e cuidado.\n\n👉 GARANTIR O MEU: https://www.ofertashop.com.br/produto/82adb4d1-a3b0-4850-87e3-59a863402f60\n\n#PresenteDiaDasMae #Natura #CabeloPerfeito", "versao_curta": "🔥 KIT ANTIQUEDA NATURA 40% OFF! Presente Dia das Maes ideal. Reduz queda, fortalece e hidrata. Por R$ 90,42. Compre ja 👉 https://www.ofertashop.com.br/produto/82adb4d1-a3b0-4850-87e3-59a863402f60"}, "tiktok_shorts": {"roteiro": "[HOOK - 0-3s] (Tela preta com som de sino de caixa registradora) Texto grande: \"KIT ANTIQUEDA VIRALIZOU E CUSTA 40% MENOS\