INSERT INTO public.products VALUES ('b92d47e8-b13d-41c2-8fa6-c9161f9dd96d', 'Britânia Escova Secadora Bec02pr 4 Em 1 1300w Cor Preto e Rosa', 'A escova ideal para o seu dia a dia e perfeita para você! A Escova Secadora Britânia BEC02 Soft 4 em 1 Tourmaline 1300W possui revestimento do tubo em cerâmica que evitam o ressecamento e o atrito, protegendo os fios do calor e proporcionando brilho ao cabelo. Perfeita para secar, alisar, modelar e dar volume. Conte com cerdas ultra macias, com pontas emborrachadas e resistentes ao calor que não agridem os fios, além de proporcionarem mais brilho. Elas reduzem o atrito na escovação e com isso diminui os danos aos cabelos, separando os fios de maneira suave, selando as cutículas, e diminuindo o efeito frizz com maior eficiência. Seu formato possui bordas arredondadas que ajudam a criar volume, além de ser ergonômico e leve.

• Pode ser usado como secador de cabelos
• Três opções de temperatura e duas opções de velocidade
• Cordão de alimentação de 1,8 metros
• Anel pendurador, que facilita o uso
• Cerdas com pontas emborrachadas
• Cordão giratório (360°)
• Libera íons
• Revestimento do tubo de aquecimento em cerâmica
• Composição: Plástico e Metal.', 99.9, 139, NULL, 'https://http2.mlstatic.com/D_NQ_NP_2X_877904-MLA99432213078_112025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_877904-MLA99432213078_112025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_789013-MLU75209974884_032024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_826711-MLU75209974896_032024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_705973-MLU75357973625_032024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_976139-MLU75862654001_042024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_704706-MLU73214035651_122023-F.webp}', 'Novo', 'Mercado Livre Eletronicos', 'https://meli.la/2xkPNQr', 4.8, 0, 0, true, NULL, '2026-04-01 22:16:30.679746+00', '2026-04-02 11:19:52.02944+00', '64dd9884-d820-4ac3-aaaf-3edaa63833d5', NULL, '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 28.1, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '95a00be7-7f36-4590-a2d9-f78cd0a12689', NULL, 16, 100000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{"latest": {"feed": {"legendas": ["Descubra a escova Britânia BEC02 4 em 1 que seca, alisa, modela e da volume!\n\nCom 1300W e revestimento em ceramica, protege os fios do calor, deixando-os brilhantes e saudaveis.\n\nAproveite: de R$ 139,00 por R$ 88,00! Desconto de 37% so hoje.\n\nGaranta ja a sua! Link na bio 👆\n\n#escovasecadora #britania #cabelos #beleza #desconto #maquiagem #cabelosaudavel #protecaocapilar #brilho #volume", "A Escova Secadora Britânia tem cerdas ultra macias com pontas emborrachadas que nao agridem os fios.\n\nIdeal para o dia a dia, voce seca, alisa, modela e da volume com praticidade e seguranca.\n\nAvaliacao 4.8/5 estrelas!\n\nNao perca: R$ 88,00 com 37% off. Link na bio 👆\n\n#cabelosperfeitos #escovasecadora #britania #beauty #haircare #desconto #promocao #cabelossaudaveis #brilho #volume", "Ultimas unidades! Escova Secadora Britânia 4 em 1 com 1300W e revestimento ceramico.\n\nProteja seus cabelos do calor enquanto seca, alisa, modela e da volume. Cerdas especiais para maximo brilho.\n\nDe R$ 139,00 por R$ 88,00. Aproveite o menor preco! 👇\n\nLink na bio para comprar!\n\n#ofertadodia #escovasecadora #britania #cabelos #beleza #desconto #promocao #cabelosaudavel #protecao #brilho"]}, "reels": {"cenas": [{"cena": 1, "audio": "Som de ''cha-ching'' e efeito surpresa", "duracao": "0-3s", "acao_visual": "Close rapido na escova Britânia em fundo preto, numero R$ 88,00 piscando", "texto_sobreposto": "POR APENAS R$ 88,00?"}, {"cena": 2, "audio": "Narracao: ''Conheca a escova 4 em 1 que faz tudo por voce.''", "duracao": "2-3s", "acao_visual": "Escova girando suavemente, destaque para design ergonomico e cores preto e rosa", "texto_sobreposto": "4 EM 1: SECA | ALISA | MODELAR | VOLUME"}, {"cena": 3, "audio": "Narracao: ''Ela evita o ressecamento e o atrito.''", "duracao": "2-3s", "acao_visual": "Close no revestimento ceramico do tubo, textura visivel", "texto_sobreposto": "CERAMICA PROTEGE OS FIOS DO CALOR"}, {"cena": 4, "audio": "Narracao: ''Secagem rapida e eficiente.''", "duracao": "2-3s", "acao_visual": "Cabelo sendo modelado (apenas cabelo, sem rosto), fluxo de ar visivel", "texto_sobreposto": "1300W DE POTENCIA"}, {"cena": 5, "audio": "Narracao: ''Nao agridem os fios, so brilho.''", "duracao": "2-3s", "acao_visual": "Cerdas da escova em close, movimento suave", "texto_sobreposto": "CERDAS ULTRA MACIAS SEM DANOS"}, {"cena": 6, "audio": "Narracao: ''Millhares de clientes aprovam!''", "duracao": "2-3s", "acao_visual": "Tela dividida: esquerda preco antigo R$ 139,00, direita preco novo R$ 88,00 e selo 37% OFF", "texto_sobreposto": "AVALIACAO 4.8/5 ESTRELAS"}, {"cena": 7, "audio": "Narracao: ''Corre que acaba! Link na bio.''", "duracao": "2-3s", "acao_visual": "Escova centralizada com seta apontando para cima (bio) e texto ''LINK NA BIO''", "texto_sobreposto": "GARANTA JA A SUA!"}], "audio_sugerido": "Happy Vibrant Pop Song - Trending on Instagram"}, "stories": {"enquete": {