INSERT INTO public.products VALUES ('12eebc12-850a-4013-b406-fcdcb03d20f9', 'Prendedor De Cortina Magnética Organizador Enfeite', '<p>Introdução do Produto:</p><p>Nome do Produto: Pérola Curtain Magnet Buckle</p><p>Cor do produto: Aleatório！！！</p><p>Material do produto: Fivela magnética da pérola da imitação + corda tecida</p><p>Tamanho do produto: Comprimento da corda 45 centímetros</p><p>Incluindo:1/2/3 Pcs cintas de cortina magnética</p><p>Características:</p><p>1. estilo europeu é elegante e elegante. E acessórios de cortina atraentes tornam sua vida mais brilhante e elegante.</p><p>O que uma pessoa precisa é de uma cortina de laço, e ela também não precisa de você. Todos podem instalá-lo facilmente.</p><p>3. ímãs de alta sucção têm qualidade. Quando você aplica a força suavemente, pode ser estável e facilmente mantido junto com as cortinas.</p><p>4. cordas de alta qualidade são resistentes e duráveis, e podem ser usadas por um longo tempo.</p><p>5. o estilo pérola é simples, bonito e generoso, o que pode tornar as cortinas mais elegantes e bonitas, e pode decorar itens domésticos com simplicidade e elegância.</p><p>Cortinas espalhadas podem ser organizadas para tornar a casa mais bonita e arrumada.</p><p>  Se você precisar pedir mais, entre em contato com o serviço ao cliente. </p>', 8.99, 12.99, NULL, 'https://cf.shopee.com.br/file/br-11134207-820li-mmec0c8tmc5c1d', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.8799331106768122.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.9133777186081036.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.1766651731801273.webp}', NULL, 'BEST MO', 'https://s.shopee.com.br/7KsjRbPkgz', 4.9, 0, 1, true, NULL, '2026-04-02 16:55:21.208854+00', '2026-04-02 17:05:58.579039+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, 30.8, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 15, 3775, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 20398530036, "shopee_shopid": 569114904}', '{}');
INSERT INTO public.products VALUES ('0813c095-39ff-46cc-a5f7-756c8c75f2d6', 'Faqueiro Tramontina Búzios Em Aço Inox Com Detalhe 24 Peças', '<p>Conjunto de Talheres 24 Peças Inox Búzios Tramontina</p><p><br></p><p>Encante amigos e familiares com o Faqueiro Tramontina Búzios em Aço Inox com Detalhe 24 Peças!</p><p><br></p><p>Produzido totalmente em aço inox, o faqueiro é resistente e durável, proporcionando uma composição mais especial para sua mesa. As peças possuem acabamento de qualidade, agregando charme às refeições.</p><p><br></p><p>As peças são fáceis de limpar e podem ser lavadas na máquina de lavar louças.</p><p><br></p><p>- Talheres produzidos em aço inox que mantêm a beleza, higiene e durabilidade.</p><p>- Lâminas das facas com maior durabilidade do fio devido ao tratamento térmico.</p><p>- Garfos e colheres com maior resistência devido à espessura do aço e estampagem das lâminas.</p><p>- Adequados para máquina de lavar louças.</p><p><br></p><p>Kit composto por:</p><p>- 06 Colher de Mesa.</p><p>- 06 Colher de Chá.</p><p>- 06 Faca para Churrasco.</p><p>- 06 Garfo de Mesa.</p><p><br></p><p>Certificação NSF - Produtos da Linha Búzios certificados pela National Sanitation Foundation (NSF), organização reconhecida em segurança alimentar e práticas de higiene.</p>', 61.97, NULL, 53, 'https://cf.shopee.com.br/file/sg-11134201-7rav5-mau2af5mj0b49f', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.043083503407627344.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.7379721631452556.webp}', 'Mais Vendidos', 'ATOZ DISTRIBUIDORA', 'https://s.shopee.com.br/4VYIC7Mkii', 4.9, 0, 4, true, NULL, '2026-03-23 18:02:39.092911+00', '2026-04-02 18:38:04.831732+00', '1a071b94-6208-4fc3-bfa5-2fc6be200de4', '0993958d-8938-48aa-b0d8-93f92a912f96', '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, NULL, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 11, 916, '[]', NULL, '{}', '{}');
INSERT INTO public.products VALUES ('9bee40e5-25b1-48dc-9ecc-fddb8b12ac07', 'Cafeteira Elétrica Electrolux Jarra vidro, acabamento inox filtro Permanente Removível Sistema Corta Pingos Capacidade 15 xicaras 600ml ECM10​', 'Com a Cafeteira Elétrica Electrolux Efficient ECM10, você prepara um delicioso cafezinho e ainda deixa a cozinha muito mais bonita, devido a seu detalhe moderno em aço inoxidável escovado.

Você pode obter até 15 cafezinhos a cada preparo com a jarra de 600ml. Além da boa capacidade, a cafeteira inox é compacta. Seu filtro lavável e removível é mais sustentável e econômico, já que o uso do filtro de papel se torna opcional; use apenas se desejar.

Completa, esta Cafeteira electrolux conta com Função Manter Aquecido, ideal para deixar sua bebida quentinha até depois de pronta. Aproveite para servir o café antes mesmo de finalizar o processo de passá-lo sem se preocupar em derramar gotas de café na base, graças ao Sistema Corta-Pingos.

O indicador de nível de água transparente permite que você veja a quantidade de água usada no preparo do café e a jarra de vidro resistente pode ser lavada facilmente na lava-louças. Tenha o melhor dos aparelhos Electrolux em sua casa e deixe sua cozinha muito mais moderna.', 109, 129, NULL, 'https://http2.mlstatic.com/D_NQ_NP_2X_890103-MLA99508244310_112025-F.webp', '{https://http2.mlstatic.com/D_NQ_NP_2X_890103-MLA99508244310_112025-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_750723-MLU75990828225_042024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_784799-MLU75990828229_042024-F.webp,https://http2.mlstatic.com/D_NQ_NP_2X_685946-MLA87641519883_072025-F.webp}', 'Novo', 'Loja oficialElectrolux', 'https://meli.la/1GRhNkn', 4.8, 0, 1, true, NULL, '2026-04-02 17:36:28.357247+00', '2026-04-02 17:38:16.998388+00', '5564c050-fcdb-4c75-a7ca-dd77d39ff4a0', 'c5a82439-f6d1-4147-8723-0feebf4f3608', '470eab59-13aa-43e1-84f0-71712bd56389', NULL, 15.5, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '1cf6748a-3b9d-4d59-8946-dedaad54eea3', NULL, 5, 10000, NULL, 99, '{"cashback": "", "meli_plus": false, "variations": [], "shipping_details": "Frete Grátis", "seller_reputation": ""}', '{}');
INSERT INTO public.products VALUES ('6ed6ad8b-bad8-4f49-b494-3a17e24202a7', 'WAP Aspirador Automotivo Portátil 12V, 420ML SÓLIDO, FILTRO HEPA, CABO DE 3,7M CAR 12V3', 'Aspirador WAP CAR 12V3: limpeza prática e eficiente para seu carro
Filtro HEPA e acessórios para alcançar todas as áreas do veículo
Leve e compacto, fácil de armazenar com recipiente lavável', 89.89, 119.9, NULL, 'https://m.media-amazon.com/images/I/71K2Aq3G60L._AC_SL1500_.jpg', '{https://m.media-amazon.com/images/I/71K2Aq3G60L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61hUcwgwK-L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/81pN0bsrajL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/814kR7mhY5L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/81dPLuEDduL._AC_SL1500_.jpg}', 'Ofertas 4.4', 'WAP', 'https://amzn.to/4m5uv6t', 5, 0, 0, true, NULL, '2026-04-02 18:16:46.873684+00', '2026-04-02 18:19:39.394435+00', 'b6ef72ee-9496-452c-903b-04e9f0b622a4', NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 25.0, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '1cf6748a-3b9d-4d59-8946-dedaad54eea3', 'B0G5Z3PZPW', 7, 6000, '[{"name": "Marca", "value": "WAP"}, {"name": "Características especiais", "value": "CompactoAlta potência, Filtro lavável, HEPA, Portátil"}, {"name": "Tipo de filtro", "value": "Filtro HEPA"}, {"name": "Recomendação de superfície", "value": "Estofos"}, {"name": "Fonte de alimentação", "value": "Alimentado por 12V"}]', NULL, '{"prime": false, "shipping_details": "Entrega GRÁTIS: Domingo, 5 de Abril Domingo, 5 de Abril"}', '{"latest": {"feed": {"legendas": ["SEU CARRO Sujo? PARE DE GASTAR EM LAVAGEM!\n\nO WAP Aspirador 12V3 caiu de R$119,90 para R$89,89.\n\nLIMPEZA PROFISSIONAL na palma da mão. Filtro HEPA, cabo de 3,7M e 420ML de pó sólido.\n\nAvaliação 5/5 ⭐⭐⭐⭐⭐\n\nNão é promoção. É RESTOCK por tempo LIMITADO.\n\n✅ Comente ''QUERO'' que eu envio o link na DM\n\n#CarroLimpo #AspiradorCarro", "FREte GRÁTIS? NÃO. Mas o DESCONTO compensa.\n\nCompare: R$89,89 vs R$119,90. ECONOMIA REAL de R$30,01.\n\nWAP CAR 12V3: Filtro HEPA [ar mais puro], Leve [guarda em qualquer lugar], 420ML [muita capacidade].\n\nÚLTIMAS 30 UNIDADES no preço baixo. Quando acabar, VOLTA pro preço cheio.\n\n👉 Link na BIO para garantir o seu antes que zere o estoque.\n\n#DescontoReal #Oferta", "VOCÊ ESTÁ P