INSERT INTO public.products VALUES ('b05c195c-37f3-42f7-b6c1-60956ef46d62', 'Cadeira de escritório Diretor Malcom Preta Healer', 'CONFORTO E RESPIRABILIDADE: Encosto em tela mesh que melhora a circulação de ar e assento de alta densidade que oferece suporte confortável para o dia todo.
AJUSTES ESSENCIAIS: Sistema relax e regulagem de altura a gás para adaptar a cadeira à sua mesa e à sua postura.
PRATICIDADE NO USO: Apoios de braço retráteis que proporcionam mais liberdade de movimento e economia de espaço.
DESIGN MODERNO E RESISTENTE: Base durável e acabamento clean na cor preta, ideal para escritório e home office.', 279.9, 419.9, NULL, 'https://m.media-amazon.com/images/I/711ggWEAs-L._AC_SL1500_.jpg', '{https://m.media-amazon.com/images/I/711ggWEAs-L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61G9sbC+h7L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/61wFmzsVBTL._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71GdZslSN+L._AC_SL1500_.jpg,https://m.media-amazon.com/images/I/71cKlHQGiEL._AC_SL1500_.jpg}', 'Escolha da AmazonOfertas 4.4', 'Healer', 'https://amzn.to/4e03K14', 4.5, 0, 0, true, NULL, '2026-04-02 22:46:26.552139+00', '2026-04-02 22:47:42.158966+00', NULL, NULL, '31640105-56f9-43ab-8204-465c8717d731', NULL, 33.3, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', 'B0D6CZSV8B', 8, 400, '[{"name": "Marca", "value": "Healer"}, {"name": "Cor", "value": "Preto"}, {"name": "Material", "value": "Metal, Plástico"}, {"name": "Dimensões do produto", "value": "54P x 56L x 104A centímetros"}, {"name": "Tamanho", "value": "54 cm x 56 cm x 104 cm"}]', NULL, '{"prime": false, "shipping_details": "Entrega GRÁTIS: 8 - 9 de Abril. Ver detalhes 8 - 9 de Abril"}', '{}');
INSERT INTO public.products VALUES ('e35070fb-2a74-4f02-840b-d1419b97ea84', 'ITEM DECORATIVO - Cruz Meu Coração Incentivo Presente Portátil De Madeira', '<p>Descrição da descrição:</p><p>Apresentando a cruz de madeira de oliva, um belo e significativo paixão que proporciona conforto durante os tempos difíceis.</p><p>Feito de madeira de pinho de alta qualidade com artesanato requintado, esta cruz é polida à perfeição, oferecendo uma textura suave que é suave nas mãos.</p><p>Seu design leve e portátil tornam conveniente carregar em seu poeta ou segurar na palma da mão como lembrete da graça de Deus, amor e misericórdia de Deus.</p><p>A cruz pequena serve como fonte de força e tranquilidade para indivíduos que enfrentam doença, tristeza ou incerteza.</p><p>Pode ajudar a facilitar os medos das crianças, proporcionar conforto para adultos que lidam com estresse e preocupações, e serve como ponto focal para oração para si e idosos.</p><p>Seja dado como presente para quem encontrou recentemente fé ou compartilhado com aqueles passando por tempos desafiadores ou perda, a cruz de madeira de oliva é um gesto pensativo e edificante.</p><p>Abrace o poder da fé e do desconforto em saber que Deus está com você a cada passo do caminho.</p><p>A cruz lindamente trabalhada seja um símbolo de esperança e suporte em tempos de necessidade.</p><p>Nome da madeira: Cruz</p><p>Material da Caixa: Madeira Material:</p><p>Alívio de estresse</p><p>Detalhes do tamanho: como mostrado</p><p>Notas de Aviso:</p><p>Devido à diferença de configuração de luz e tela, a cor do item pode ser ligeiramente diferente das fotos.</p><p>Por favor, permita uma ligeira diferença de dimensão devido a diferentes medidas manuais.</p><p>A página de 3 peças inclui: 3 peças</p>', 17.49, NULL, 53, 'https://cf.shopee.com.br/file/sg-11134201-8260z-mk84k5py7fgkb7', '{https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.07572119861156501.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.8010361245630706.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.15150036332184968.webp,https://smfndfyuscgfjedeqysu.supabase.co/storage/v1/object/public/product-images/0.1298518439469688.webp}', NULL, 'aredmoon.br', 'https://s.shopee.com.br/1gEMgialXN', 5, 0, 0, true, NULL, '2026-04-02 16:48:56.52907+00', '2026-04-02 18:38:22.671525+00', NULL, NULL, '5a54bf84-4707-4f0f-a23c-689469fdbbb7', NULL, NULL, 'ae8dfd8c-5182-41d7-9a4a-c02ebba36890', '4892e78b-d2cc-43b8-8a17-605b03f1d4a3', NULL, 3, 29, '[]', NULL, '{"price_source": "graphql_api", "shopee_itemid": 47356050746, "shopee_shopid": 303325540}', '{}');
INSERT INTO public.products VALUES ('62f6eefd-9ccc-41bd-8242-4134cdb7941b', 'Sabonete Monodose para as Mãos Ekos Castanha', '<p><strong>1º sabonete monodose para as mãos com fórmula exclusiva Natura.</strong></p><p><strong>•</strong>&nbsp;inovação perfeita para levar e usar em&nbsp;<strong>qualquer lugar</strong></p><p><strong>•</strong>&nbsp;o sabonete que você já conhece agora em&nbsp;<strong>doses unitárias</strong></p><p><strong>•</strong>&nbsp;mais prático para você e&nbsp;<strong>menos plástico</strong>&nbsp;para o planeta</p><p><strong>•</strong>&nbsp;toda potência da castanha para limpar, nutrir, hidratar e perfumar sua pele</p><p><strong>•</strong>&nbsp;espuma cremosa que deixa suas&nbsp;<strong>mãos macias e aveludadas</strong></p><p><strong>•</strong>&nbsp;fragrância&nbsp;<strong>deliciosa e aconchegante</strong>&nbsp;de castanha</p><p><strong>•</strong>&nbsp;forma um filme protetor nas mãos, respeitando a barreira de&nbsp;<strong>hidratação</strong>&nbsp;da sua pele.</p><p>&nbsp;</p><p><strong>contém</strong></p><p>embalagem com 30 unidades de 500 miligramas cada.</p>', 25.9, 39.9, NULL, 'https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwaf6d0509/NATBRA-139242_1.jpg?sw=300&q=80', '{https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwaf6d0509/NATBRA-139242_1.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwaf6d0509/NATBRA-139242_2.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwaf6d0509/NATBRA-139242_3.jpg?sw=300&q=80,https://production.na01.natura.com/dw/image/v2/BFKR_PRD/on/demandware.static/-/Sites-natura-br-storefront-catalog/default/dwaf6d0509/NATBRA-139242_4.jpg?sw=300&q=80}', '35% OFF', 'Natura', 'https://minhaloja.natura.com